-- V18: Seed EN translations juz11_15

INSERT INTO mst_translation (ayah_id, language_id, translator_name, text,
                             created_at, updated_at)
VALUES
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The cause [for blame] is only upon those who ask permission of you while they are rich. They are satisfied to be with those who stay behind, and Allah has sealed over their hearts, so they do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will make excuses to you when you have returned to them. Say, "Make no excuse - never will we believe you. Allah has already informed us of your news. And Allah will observe your deeds, and [so will] His Messenger; then you will be taken back to the Knower of the unseen and the witnessed, and He will inform you of what you used to do."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will swear by Allah to you when you return to them that you would leave them alone. So leave them alone; indeed they are evil; and their refuge is Hell as recompense for what they had been earning.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They swear to you so that you might be satisfied with them. But if you should be satisfied with them - indeed, Allah is not satisfied with a defiantly disobedient people.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The bedouins are stronger in disbelief and hypocrisy and more likely not to know the limits of what [laws] Allah has revealed to His Messenger. And Allah is Knowing and Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And among the bedouins are some who consider what they spend as a loss and await for you turns of misfortune. Upon them will be a misfortune of evil. And Allah is Hearing and Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But among the bedouins are some who believe in Allah and the Last Day and consider what they spend as means of nearness to Allah and of [obtaining] invocations of the Messenger. Unquestionably, it is a means of nearness for them. Allah will admit them to His mercy. Indeed, Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the first forerunners [in the faith] among the Muhajireen and the Ansar and those who followed them with good conduct - Allah is pleased with them and they are pleased with Him, and He has prepared for them gardens beneath which rivers flow, wherein they will abide forever. That is the great attainment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And among those around you of the bedouins are hypocrites, and [also] from the people of Madinah. They have become accustomed to hypocrisy. You, [O Muhammad], do not know them, [but] We know them. We will punish them twice [in this world]; then they will be returned to a great punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [there are] others who have acknowledged their sins. They had mixed a righteous deed with another that was bad. Perhaps Allah will turn to them in forgiveness. Indeed, Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Take, [O, Muhammad], from their wealth a charity by which you purify them and cause them increase, and invoke [Allah ''s blessings] upon them. Indeed, your invocations are reassurance for them. And Allah is Hearing and Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they not know that it is Allah who accepts repentance from His servants and receives charities and that it is Allah who is the Accepting of repentance, the Merciful?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And say, "Do [as you will], for Allah will see your deeds, and [so, will] His Messenger and the believers. And you will be returned to the Knower of the unseen and the witnessed, and He will inform you of what you used to do."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [there are] others deferred until the command of Allah - whether He will punish them or whether He will forgive them. And Allah is Knowing and Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [there are] those [hypocrites] who took for themselves a mosque for causing harm and disbelief and division among the believers and as a station for whoever had warred against Allah and His Messenger before. And they will surely swear, "We intended only the best." And Allah testifies that indeed they are liars.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do not stand [for prayer] within it - ever. A mosque founded on righteousness from the first day is more worthy for you to stand in. Within it are men who love to purify themselves; and Allah loves those who purify themselves.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then is one who laid the foundation of his building on righteousness [with fear] from Allah and [seeking] His approval better or one who laid the foundation of his building on the edge of a bank about to collapse, so it collapsed with him into the fire of Hell? And Allah does not guide the wrongdoing people.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their building which they built will not cease to be a [cause of] skepticism in their hearts until their hearts are stopped. And Allah is Knowing and Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah has purchased from the believers their lives and their properties [in exchange] for that they will have Paradise. They fight in the cause of Allah, so they kill and are killed. [It is] a true promise [binding] upon Him in the Torah and the Gospel and the Qur''an. And who is truer to his covenant than Allah? So rejoice in your transaction which you have contracted. And it is that which is the great attainment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 112), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Such believers are] the repentant, the worshippers, the praisers [of Allah], the travelers [for His cause], those who bow and prostrate [in prayer], those who enjoin what is right and forbid what is wrong, and those who observe the limits [set by] Allah. And give good tidings to the believers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 113), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is not for the Prophet and those who have believed to ask forgiveness for the polytheists, even if they were relatives, after it has become clear to them that they are companions of Hellfire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 114), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the request of forgiveness of Abraham for his father was only because of a promise he had made to him. But when it became apparent to Abraham that his father was an enemy to Allah, he disassociated himself from him. Indeed was Abraham compassionate and patient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 115), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah would not let a people stray after He has guided them until He makes clear to them what they should avoid. Indeed, Allah is Knowing of all things.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 116), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, to Allah belongs the dominion of the heavens and the earth; He gives life and causes death. And you have not besides Allah any protector or any helper.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 117), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah has already forgiven the Prophet and the Muhajireen and the Ansar who followed him in the hour of difficulty after the hearts of a party of them had almost inclined [to doubt], and then He forgave them. Indeed, He was to them Kind and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 118), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [He also forgave] the three who were left behind [and regretted their error] to the point that the earth closed in on them in spite of its vastness and their souls confined them and they were certain that there is no refuge from Allah except in Him. Then He turned to them so they could repent. Indeed, Allah is the Accepting of repentance, the Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 119), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, fear Allah and be with those who are true.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 120), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It was not [proper] for the people of Madinah and those surrounding them of the bedouins that they remain behind after [the departure of] the Messenger of Allah or that they prefer themselves over his self. That is because they are not afflicted by thirst or fatigue or hunger in the cause of Allah, nor do they tread on any ground that enrages the disbelievers, nor do they inflict upon an enemy any infliction but that is registered for them as a righteous deed. Indeed, Allah does not allow to be lost the reward of the doers of good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 121), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor do they spend an expenditure, small or large, or cross a valley but that it is registered for them that Allah may reward them for the best of what they were doing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 122), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is not for the believers to go forth [to battle] all at once. For there should separate from every division of them a group [remaining] to obtain understanding in the religion and warn their people when they return to them that they might be cautious.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 123), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, fight those adjacent to you of the disbelievers and let them find in you harshness. And know that Allah is with the righteous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 124), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whenever a surah is revealed, there are among the hypocrites those who say, "Which of you has this increased faith?" As for those who believed, it has increased them in faith, while they are rejoicing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 125), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for those in whose hearts is disease, it has [only] increased them in evil [in addition] to their evil. And they will have died while they are disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 126), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they not see that they are tried every year once or twice but then they do not repent nor do they remember?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 127), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whenever a surah is revealed, they look at each other, [saying], "Does anyone see you?" and then they dismiss themselves. Allah has dismissed their hearts because they are a people who do not understand.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 128), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There has certainly come to you a Messenger from among yourselves. Grievous to him is what you suffer; [he is] concerned over you and to the believers is kind and merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 9 AND a.ayah_number = 129), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if they turn away, [O Muhammad], say, "Sufficient for me is Allah; there is no deity except Him. On Him I have relied, and He is the Lord of the Great Throne."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Alif, Lam, Ra. These are the verses of the wise Book', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have the people been amazed that We revealed [revelation] to a man from among them, [saying], "Warn mankind and give good tidings to those who believe that they will have a [firm] precedence of honor with their Lord"? [But] the disbelievers say, "Indeed, this is an obvious magician."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, your Lord is Allah, who created the heavens and the earth in six days and then established Himself above the Throne, arranging the matter [of His creation]. There is no intercessor except after His permission. That is Allah, your Lord, so worship Him. Then will you not remember?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To Him is your return all together. [It is] the promise of Allah [which is] truth. Indeed, He begins the [process of] creation and then repeats it that He may reward those who have believed and done righteous deeds, in justice. But those who disbelieved will have a drink of scalding water and a painful punishment for what they used to deny.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who made the sun a shining light and the moon a derived light and determined for it phases - that you may know the number of years and account [of time]. Allah has not created this except in truth. He details the signs for a people who know', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, in the alternation of the night and the day and [in] what Allah has created in the heavens and the earth are signs for a people who fear Allah', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who do not expect the meeting with Us and are satisfied with the life of this world and feel secure therein and those who are heedless of Our signs', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For those their refuge will be the Fire because of what they used to earn.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who have believed and done righteous deeds - their Lord will guide them because of their faith. Beneath them rivers will flow in the Gardens of Pleasure', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their call therein will be, "Exalted are You, O Allah," and their greeting therein will be, "Peace." And the last of their call will be, "Praise to Allah, Lord of the worlds!"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if Allah was to hasten for the people the evil [they invoke] as He hastens for them the good, their term would have been ended for them. But We leave the ones who do not expect the meeting with Us, in their transgression, wandering blindly', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when affliction touches man, he calls upon Us, whether lying on his side or sitting or standing; but when We remove from him his affliction, he continues [in disobedience] as if he had never called upon Us to [remove] an affliction that touched him. Thus is made pleasing to the transgressors that which they have been doing', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had already destroyed generations before you when they wronged, and their messengers had come to them with clear proofs, but they were not to believe. Thus do We recompense the criminal people', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We made you successors in the land after them so that We may observe how you will do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when Our verses are recited to them as clear evidences, those who do not expect the meeting with Us say, "Bring us a Qur''an other than this or change it." Say, [O Muhammad], "It is not for me to change it on my own accord. I only follow what is revealed to me. Indeed I fear, if I should disobey my Lord, the punishment of a tremendous Day."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "If Allah had willed, I would not have recited it to you, nor would He have made it known to you, for I had remained among you a lifetime before it. Then will you not reason?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So who is more unjust than he who invents a lie about Allah or denies His signs? Indeed, the criminals will not succeed', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they worship other than Allah that which neither harms them nor benefits them, and they say, "These are our intercessors with Allah " Say, "Do you inform Allah of something He does not know in the heavens or on the earth?" Exalted is He and high above what they associate with Him', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And mankind was not but one community [united in religion], but [then] they differed. And if not for a word that preceded from your Lord, it would have been judged between them [immediately] concerning that over which they differ.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "Why is a sign not sent down to him from his Lord?" So say, "The unseen is only for Allah [to administer], so wait; indeed, I am with you among those who wait."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when We give the people a taste of mercy after adversity has touched them, at once they conspire against Our verses. Say, "Allah is swifter in strategy." Indeed, Our messengers record that which you conspire', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who enables you to travel on land and sea until, when you are in ships and they sail with them by a good wind and they rejoice therein, there comes a storm wind and the waves come upon them from everywhere and they assume that they are surrounded, supplicating Allah, sincere to Him in religion, "If You should save us from this, we will surely be among the thankful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when He saves them, at once they commit injustice upon the earth without right. O mankind, your injustice is only against yourselves, [being merely] the enjoyment of worldly life. Then to Us is your return, and We will inform you of what you used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The example of [this] worldly life is but like rain which We have sent down from the sky that the plants of the earth absorb - [those] from which men and livestock eat - until, when the earth has taken on its adornment and is beautified and its people suppose that they have capability over it, there comes to it Our command by night or by day, and We make it as a harvest, as if it had not flourished yesterday. Thus do We explain in detail the signs for a people who give thought.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah invites to the Home of Peace and guides whom He wills to a straight path', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For them who have done good is the best [reward] and extra. No darkness will cover their faces, nor humiliation. Those are companions of Paradise; they will abide therein eternally', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they who have earned [blame for] evil doings - the recompense of an evil deed is its equivalent, and humiliation will cover them. They will have from Allah no protector. It will be as if their faces are covered with pieces of the night - so dark [are they]. Those are the companions of the Fire; they will abide therein eternally.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention, O Muhammad], the Day We will gather them all together - then We will say to those who associated others with Allah, "[Remain in] your place, you and your ''partners.'' " Then We will separate them, and their "partners" will say, "You did not used to worship us,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And sufficient is Allah as a witness between us and you that we were of your worship unaware."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There, [on that Day], every soul will be put to trial for what it did previously, and they will be returned to Allah, their master, the Truth, and lost from them is whatever they used to invent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Who provides for you from the heaven and the earth? Or who controls hearing and sight and who brings the living out of the dead and brings the dead out of the living and who arranges [every] matter?" They will say, "Allah," so say, "Then will you not fear Him?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For that is Allah, your Lord, the Truth. And what can be beyond truth except error? So how are you averted?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Thus the word of your Lord has come into effect upon those who defiantly disobeyed - that they will not believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Are there of your ''partners'' any who begins creation and then repeats it?" Say, "Allah begins creation and then repeats it, so how are you deluded?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Are there of your ''partners'' any who guides to the truth?" Say, "Allah guides to the truth. So is He who guides to the truth more worthy to be followed or he who guides not unless he is guided? Then what is [wrong] with you - how do you judge?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And most of them follow not except assumption. Indeed, assumption avails not against the truth at all. Indeed, Allah is Knowing of what they do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it was not [possible] for this Qur''an to be produced by other than Allah, but [it is] a confirmation of what was before it and a detailed explanation of the [former] Scripture, about which there is no doubt, from the Lord of the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do they say [about the Prophet], "He invented it?" Say, "Then bring forth a surah like it and call upon [for assistance] whomever you can besides Allah, if you should be truthful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Rather, they have denied that which they encompass not in knowledge and whose interpretation has not yet come to them. Thus did those before them deny. Then observe how was the end of the wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of them are those who believe in it, and of them are those who do not believe in it. And your Lord is most knowing of the corrupters', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if they deny you, [O Muhammad], then say, "For me are my deeds, and for you are your deeds. You are disassociated from what I do, and I am disassociated from what you do."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And among them are those who listen to you. But can you cause the deaf to hear, although they will not use reason?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And among them are those who look at you. But can you guide the blind although they will not [attempt to] see?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah does not wrong the people at all, but it is the people who are wronging themselves.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And on the Day when He will gather them, [it will be] as if they had not remained [in the world] but an hour of the day, [and] they will know each other. Those will have lost who denied the meeting with Allah and were not guided', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whether We show you some of what We promise them, [O Muhammad], or We take you in death, to Us is their return; then, [either way], Allah is a witness concerning what they are doing', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And for every nation is a messenger. So when their messenger comes, it will be judged between them in justice, and they will not be wronged', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "When is [the fulfillment of] this promise, if you should be truthful?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "I possess not for myself any harm or benefit except what Allah should will. For every nation is a [specified] term. When their time has come, then they will not remain behind an hour, nor will they precede [it]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Have you considered: if His punishment should come to you by night or by day - for which [aspect] of it would the criminals be impatient?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then is it that when it has [actually] occurred you will believe in it? Now? And you were [once] for it impatient', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then it will be said to those who had wronged, "Taste the punishment of eternity; are you being recompensed except for what you used to earn?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they ask information of you, [O Muhammad], "Is it true?" Say, "Yes, by my Lord. Indeed, it is truth; and you will not cause failure [to Allah]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if each soul that wronged had everything on earth, it would offer it in ransom. And they will confide regret when they see the punishment; and they will be judged in justice, and they will not be wronged', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Unquestionably, to Allah belongs whatever is in the heavens and the earth. Unquestionably, the promise of Allah is truth, but most of them do not know', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He gives life and causes death, and to Him you will be returned', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O mankind, there has to come to you instruction from your Lord and healing for what is in the breasts and guidance and mercy for the believers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "In the bounty of Allah and in His mercy - in that let them rejoice; it is better than what they accumulate."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Have you seen what Allah has sent down to you of provision of which you have made [some] lawful and [some] unlawful?" Say, "Has Allah permitted you [to do so], or do you invent [something] about Allah?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what will be the supposition of those who invent falsehood about Allah on the Day of Resurrection? Indeed, Allah is full of bounty to the people, but most of them are not grateful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And, [O Muhammad], you are not [engaged] in any matter or recite any of the Qur''an and you [people] do not do any deed except that We are witness over you when you are involved in it. And not absent from your Lord is any [part] of an atom''s weight within the earth or within the heaven or [anything] smaller than that or greater but that it is in a clear register.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Unquestionably, [for] the allies of Allah there will be no fear concerning them, nor will they grieve', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who believed and were fearing Allah', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For them are good tidings in the worldly life and in the Hereafter. No change is there in the words of Allah. That is what is the great attainment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And let not their speech grieve you. Indeed, honor [due to power] belongs to Allah entirely. He is the Hearing, the Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Unquestionably, to Allah belongs whoever is in the heavens and whoever is on the earth. And those who invoke other than Allah do not [actually] follow [His] "partners." They follow not except assumption, and they are not but falsifying', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who made for you the night to rest therein and the day, giving sight. Indeed in that are signs for a people who listen.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They have said, "Allah has taken a son." Exalted is He; He is the [one] Free of need. To Him belongs whatever is in the heavens and whatever is in the earth. You have no authority for this [claim]. Do you say about Allah that which you do not know?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Indeed, those who invent falsehood about Allah will not succeed."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[For them is brief] enjoyment in this world; then to Us is their return; then We will make them taste the severe punishment because they used to disbelieve', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And recite to them the news of Noah, when he said to his people, "O my people, if my residence and my reminding of the signs of Allah has become burdensome upon you - then I have relied upon Allah. So resolve upon your plan and [call upon] your associates. Then let not your plan be obscure to you. Then carry it out upon me and do not give me respite.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you turn away [from my advice] then no payment have I asked of you. My reward is only from Allah, and I have been commanded to be of the Muslims."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they denied him, so We saved him and those with him in the ship and made them successors, and We drowned those who denied Our signs. Then see how was the end of those who were warned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We sent after him messengers to their peoples, and they came to them with clear proofs. But they were not to believe in that which they had denied before. Thus We seal over the hearts of the transgressors', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We sent after them Moses and Aaron to Pharaoh and his establishment with Our signs, but they behaved arrogantly and were a criminal people', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when there came to them the truth from Us, they said, "Indeed, this is obvious magic."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Moses said, "Do you say [thus] about the truth when it has come to you? Is this magic? But magicians will not succeed."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "Have you come to us to turn us away from that upon which we found our fathers and so that you two may have grandeur in the land? And we are not believers in you."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Pharaoh said, "Bring to me every learned magician."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when the magicians came, Moses said to them, "Throw down whatever you will throw."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they had thrown, Moses said, "What you have brought is [only] magic. Indeed, Allah will expose its worthlessness. Indeed, Allah does not amend the work of corrupters.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah will establish the truth by His words, even if the criminals dislike it."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But no one believed Moses, except [some] youths among his people, for fear of Pharaoh and his establishment that they would persecute them. And indeed, Pharaoh was haughty within the land, and indeed, he was of the transgressors', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Moses said, "O my people, if you have believed in Allah, then rely upon Him, if you should be Muslims."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So they said, "Upon Allah do we rely. Our Lord, make us not [objects of] trial for the wrongdoing people', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And save us by Your mercy from the disbelieving people."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We inspired to Moses and his brother, "Settle your people in Egypt in houses and make your houses [facing the] qiblah and establish prayer and give good tidings to the believers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Moses said, "Our Lord, indeed You have given Pharaoh and his establishment splendor and wealth in the worldly life, our Lord, that they may lead [men] astray from Your way. Our Lord, obliterate their wealth and harden their hearts so that they will not believe until they see the painful punishment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah] said, "Your supplication has been answered." So remain on a right course and follow not the way of those who do not know."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We took the Children of Israel across the sea, and Pharaoh and his soldiers pursued them in tyranny and enmity until, when drowning overtook him, he said, "I believe that there is no deity except that in whom the Children of Israel believe, and I am of the Muslims."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Now? And you had disobeyed [Him] before and were of the corrupters?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So today We will save you in body that you may be to those who succeed you a sign. And indeed, many among the people, of Our signs, are heedless', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had certainty settled the Children of Israel in an agreeable settlement and provided them with good things. And they did not differ until [after] knowledge had come to them. Indeed, your Lord will judge between them on the Day of Resurrection concerning that over which they used to differ', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So if you are in doubt, [O Muhammad], about that which We have revealed to you, then ask those who have been reading the Scripture before you. The truth has certainly come to you from your Lord, so never be among the doubters.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And never be of those who deny the signs of Allah and [thus] be among the losers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those upon whom the word of your Lord has come into effect will not believe,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Even if every sign should come to them, until they see the painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then has there not been a [single] city that believed so its faith benefited it except the people of Jonah? When they believed, We removed from them the punishment of disgrace in worldly life and gave them enjoyment for a time.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And had your Lord willed, those on earth would have believed - all of them entirely. Then, [O Muhammad], would you compel the people in order that they become believers?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is not for a soul to believe except by permission of Allah, and He will place defilement upon those who will not use reason.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Observe what is in the heavens and earth." But of no avail will be signs or warners to a people who do not believe', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So do they wait except for like [what occurred in] the days of those who passed on before them? Say, "Then wait; indeed, I am with you among those who wait."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We will save our messengers and those who have believed. Thus, it is an obligation upon Us that We save the believers', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "O people, if you are in doubt as to my religion - then I do not worship those which you worship besides Allah; but I worship Allah, who causes your death. And I have been commanded to be of the believers', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [commanded], ''Direct your face toward the religion, inclining to truth, and never be of those who associate others with Allah;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not invoke besides Allah that which neither benefits you nor harms you, for if you did, then indeed you would be of the wrongdoers.''"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if Allah should touch you with adversity, there is no remover of it except Him; and if He intends for you good, then there is no repeller of His bounty. He causes it to reach whom He wills of His servants. And He is the Forgiving, the Merciful', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "O mankind, the truth has come to you from your Lord, so whoever is guided is only guided for [the benefit of] his soul, and whoever goes astray only goes astray [in violation] against it. And I am not over you a manager."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 10 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And follow what is revealed to you, [O Muhammad], and be patient until Allah will judge. And He is the best of judges.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Alif, Lam, Ra. [This is] a Book whose verses are perfected and then presented in detail from [one who is] Wise and Acquainted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Through a messenger, saying], "Do not worship except Allah. Indeed, I am to you from Him a warner and a bringer of good tidings,"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [saying], "Seek forgiveness of your Lord and repent to Him, [and] He will let you enjoy a good provision for a specified term and give every doer of favor his favor. But if you turn away, then indeed, I fear for you the punishment of a great Day.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To Allah is your return, and He is over all things competent."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Unquestionably, they the disbelievers turn away their breasts to hide themselves from Him. Unquestionably, [even] when they cover themselves in their clothing, Allah knows what they conceal and what they declare. Indeed, He is Knowing of that within the breasts.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there is no creature on earth but that upon Allah is its provision, and He knows its place of dwelling and place of storage. All is in a clear register.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is He who created the heavens and the earth in six days - and His Throne had been upon water - that He might test you as to which of you is best in deed. But if you say, "Indeed, you are resurrected after death," those who disbelieve will surely say, "This is not but obvious magic."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We hold back from them the punishment for a limited time, they will surely say, "What detains it?" Unquestionably, on the Day it comes to them, it will not be averted from them, and they will be enveloped by what they used to ridicule.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We give man a taste of mercy from Us and then We withdraw it from him, indeed, he is despairing and ungrateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if We give him a taste of favor after hardship has touched him, he will surely say, "Bad times have left me." Indeed, he is exultant and boastful -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except for those who are patient and do righteous deeds; those will have forgiveness and great reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then would you possibly leave [out] some of what is revealed to you, or is your breast constrained by it because they say, "Why has there not been sent down to him a treasure or come with him an angel?" But you are only a warner. And Allah is Disposer of all things.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do they say, "He invented it"? Say, "Then bring ten surahs like it that have been invented and call upon [for assistance] whomever you can besides Allah, if you should be truthful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if they do not respond to you - then know that the Qur''an was revealed with the knowledge of Allah and that there is no deity except Him. Then, would you [not] be Muslims?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever desires the life of this world and its adornments - We fully repay them for their deeds therein, and they therein will not be deprived.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those are the ones for whom there is not in the Hereafter but the Fire. And lost is what they did therein, and worthless is what they used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So is one who [stands] upon a clear evidence from his Lord [like the aforementioned]? And a witness from Him follows it, and before it was the Scripture of Moses to lead and as mercy. Those [believers in the former revelations] believe in the Qur''an. But whoever disbelieves in it from the [various] factions - the Fire is his promised destination. So be not in doubt about it. Indeed, it is the truth from your Lord, but most of the people do not believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And who is more unjust than he who invents a lie about Allah? Those will be presented before their Lord, and the witnesses will say, "These are the ones who lied against their Lord." Unquestionably, the curse of Allah is upon the wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who averted [people] from the way of Allah and sought to make it [seem] deviant while they, concerning the Hereafter, were disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those were not causing failure [to Allah] on earth, nor did they have besides Allah any protectors. For them the punishment will be multiplied. They were not able to hear, nor did they see.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those are the ones who will have lost themselves, and lost from them is what they used to invent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Assuredly, it is they in the Hereafter who will be the greatest losers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, they who have believed and done righteous deeds and humbled themselves to their Lord - those are the companions of Paradise; they will abide eternally therein.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The example of the two parties is like the blind and deaf, and the seeing and hearing. Are they equal in comparison? Then, will you not remember?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had certainly sent Noah to his people, [saying], "Indeed, I am to you a clear warner', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That you not worship except Allah. Indeed, I fear for you the punishment of a painful day."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So the eminent among those who disbelieved from his people said, "We do not see you but as a man like ourselves, and we do not see you followed except by those who are the lowest of us [and] at first suggestion. And we do not see in you over us any merit; rather, we think you are liars."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "O my people have you considered: if I should be upon clear evidence from my Lord while He has given me mercy from Himself but it has been made unapparent to you, should we force it upon you while you are averse to it?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And O my people, I ask not of you for it any wealth. My reward is not but from Allah. And I am not one to drive away those who have believed. Indeed, they will meet their Lord, but I see that you are a people behaving ignorantly.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And O my people, who would protect me from Allah if I drove them away? Then will you not be reminded?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And I do not tell you that I have the depositories [containing the provision] of Allah or that I know the unseen, nor do I tell you that I am an angel, nor do I say of those upon whom your eyes look down that Allah will never grant them any good. Allah is most knowing of what is within their souls. Indeed, I would then be among the wrongdoers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "O Noah, you have disputed us and been frequent in dispute of us. So bring us what you threaten us, if you should be of the truthful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "Allah will only bring it to you if He wills, and you will not cause [Him] failure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And my advice will not benefit you - although I wished to advise you - If Allah should intend to put you in error. He is your Lord, and to Him you will be returned."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do they say [about Prophet Muhammad], "He invented it"? Say, "If I have invented it, then upon me is [the consequence of] my crime; but I am innocent of what [crimes] you commit."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it was revealed to Noah that, "No one will believe from your people except those who have already believed, so do not be distressed by what they have been doing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And construct the ship under Our observation and Our inspiration and do not address Me concerning those who have wronged; indeed, they are [to be] drowned."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he constructed the ship, and whenever an assembly of the eminent of his people passed by him, they ridiculed him. He said, "If you ridicule us, then we will ridicule you just as you ridicule.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you are going to know who will get a punishment that will disgrace him [on earth] and upon whom will descend an enduring punishment [in the Hereafter]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[So it was], until when Our command came and the oven overflowed, We said, "Load upon the ship of each [creature] two mates and your family, except those about whom the word has preceded, and [include] whoever has believed." But none had believed with him, except a few.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [Noah] said, "Embark therein; in the name of Allah is its course and its anchorage. Indeed, my Lord is Forgiving and Merciful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it sailed with them through waves like mountains, and Noah called to his son who was apart [from them], "O my son, come aboard with us and be not with the disbelievers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[But] he said, "I will take refuge on a mountain to protect me from the water." [Noah] said, "There is no protector today from the decree of Allah, except for whom He gives mercy." And the waves came between them, and he was among the drowned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it was said, "O earth, swallow your water, and O sky, withhold [your rain]." And the water subsided, and the matter was accomplished, and the ship came to rest on the [mountain of] Judiyy. And it was said, "Away with the wrongdoing people."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Noah called to his Lord and said, "My Lord, indeed my son is of my family; and indeed, Your promise is true; and You are the most just of judges!"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "O Noah, indeed he is not of your family; indeed, he is [one whose] work was other than righteous, so ask Me not for that about which you have no knowledge. Indeed, I advise you, lest you be among the ignorant."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Noah] said, "My Lord, I seek refuge in You from asking that of which I have no knowledge. And unless You forgive me and have mercy upon me, I will be among the losers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It was said, "O Noah, disembark in security from Us and blessings upon you and upon nations [descending] from those with you. But other nations [of them] We will grant enjoyment; then there will touch them from Us a painful punishment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is from the news of the unseen which We reveal to you, [O Muhammad]. You knew it not, neither you nor your people, before this. So be patient; indeed, the [best] outcome is for the righteous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to ''Aad [We sent] their brother Hud. He said, "O my people, worship Allah; you have no deity other than Him. You are not but inventors [of falsehood].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O my people, I do not ask you for it any reward. My reward is only from the one who created me. Then will you not reason?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And O my people, ask forgiveness of your Lord and then repent to Him. He will send [rain from] the sky upon you in showers and increase you in strength [added] to your strength. And do not turn away, [being] criminals."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "O Hud, you have not brought us clear evidence, and we are not ones to leave our gods on your say-so. Nor are we believers in you.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We only say that some of our gods have possessed you with evil." He said, "Indeed, I call Allah to witness, and witness [yourselves] that I am free from whatever you associate with Allah', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Other than Him. So plot against me all together; then do not give me respite.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, I have relied upon Allah, my Lord and your Lord. There is no creature but that He holds its forelock. Indeed, my Lord is on a path [that is] straight."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if they turn away, [say], "I have already conveyed that with which I was sent to you. My Lord will give succession to a people other than you, and you will not harm Him at all. Indeed my Lord is, over all things, Guardian."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when Our command came, We saved Hud and those who believed with him, by mercy from Us; and We saved them from a harsh punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that was ''Aad, who rejected the signs of their Lord and disobeyed His messengers and followed the order of every obstinate tyrant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they were [therefore] followed in this world with a curse and [as well] on the Day of Resurrection. Unquestionably, ''Aad denied their Lord; then away with ''Aad, the people of Hud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Thamud [We sent] their brother Salih. He said, "O my people, worship Allah; you have no deity other than Him. He has produced you from the earth and settled you in it, so ask forgiveness of Him and then repent to Him. Indeed, my Lord is near and responsive."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "O Salih, you were among us a man of promise before this. Do you forbid us to worship what our fathers worshipped? And indeed we are, about that to which you invite us, in disquieting doubt."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "O my people, have you considered: if I should be upon clear evidence from my Lord and He has given me mercy from Himself, who would protect me from Allah if I disobeyed Him? So you would not increase me except in loss.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And O my people, this is the she-camel of Allah - [she is] to you a sign. So let her feed upon Allah ''s earth and do not touch her with harm, or you will be taken by an impending punishment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they hamstrung her, so he said, "Enjoy yourselves in your homes for three days. That is a promise not to be denied."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when Our command came, We saved Salih and those who believed with him, by mercy from Us, and [saved them] from the disgrace of that day. Indeed, it is your Lord who is the Powerful, the Exalted in Might.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the shriek seized those who had wronged, and they became within their homes [corpses] fallen prone', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As if they had never prospered therein. Unquestionably, Thamud denied their Lord; then, away with Thamud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And certainly did Our messengers come to Abraham with good tidings; they said, "Peace." He said, "Peace," and did not delay in bringing [them] a roasted calf.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when he saw their hands not reaching for it, he distrusted them and felt from them apprehension. They said, "Fear not. We have been sent to the people of Lot."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And his Wife was standing, and she smiled. Then We gave her good tidings of Isaac and after Isaac, Jacob.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'She said, "Woe to me! Shall I give birth while I am an old woman and this, my husband, is an old man? Indeed, this is an amazing thing!"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "Are you amazed at the decree of Allah? May the mercy of Allah and His blessings be upon you, people of the house. Indeed, He is Praiseworthy and Honorable."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the fright had left Abraham and the good tidings had reached him, he began to argue with Us concerning the people of Lot.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Abraham was forbearing, grieving and [frequently] returning [to Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[The angels said], "O Abraham, give up this [plea]. Indeed, the command of your Lord has come, and indeed, there will reach them a punishment that cannot be repelled."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when Our messengers, [the angels], came to Lot, he was anguished for them and felt for them great discomfort and said, "This is a trying day."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And his people came hastening to him, and before [this] they had been doing evil deeds. He said, "O my people, these are my daughters; they are purer for you. So fear Allah and do not disgrace me concerning my guests. Is there not among you a man of reason?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "You have already known that we have not concerning your daughters any claim, and indeed, you know what we want."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "If only I had against you some power or could take refuge in a strong support."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The angels said, "O Lot, indeed we are messengers of your Lord; [therefore], they will never reach you. So set out with your family during a portion of the night and let not any among you look back - except your wife; indeed, she will be struck by that which strikes them. Indeed, their appointment is [for] the morning. Is not the morning near?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when Our command came, We made the highest part [of the city] its lowest and rained upon them stones of layered hard clay, [which were]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Marked from your Lord. And Allah ''s punishment is not from the wrongdoers [very] far.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Madyan [We sent] their brother Shu''ayb. He said, "O my people, worship Allah; you have no deity other than Him. And do not decrease from the measure and the scale. Indeed, I see you in prosperity, but indeed, I fear for you the punishment of an all-encompassing Day.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And O my people, give full measure and weight in justice and do not deprive the people of their due and do not commit abuse on the earth, spreading corruption.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'What remains [lawful] from Allah is best for you, if you would be believers. But I am not a guardian over you."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "O Shu''ayb, does your prayer command you that we should leave what our fathers worship or not do with our wealth what we please? Indeed, you are the forbearing, the discerning!"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "O my people, have you considered: if I am upon clear evidence from my Lord and He has provided me with a good provision from Him...? And I do not intend to differ from you in that which I have forbidden you; I only intend reform as much as I am able. And my success is not but through Allah. Upon him I have relied, and to Him I return.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And O my people, let not [your] dissension from me cause you to be struck by that similar to what struck the people of Noah or the people of Hud or the people of Salih. And the people of Lot are not from you far away.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And ask forgiveness of your Lord and then repent to Him. Indeed, my Lord is Merciful and Affectionate."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "O Shu''ayb, we do not understand much of what you say, and indeed, we consider you among us as weak. And if not for your family, we would have stoned you [to death]; and you are not to us one respected."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "O my people, is my family more respected for power by you than Allah? But you put Him behind your backs [in neglect]. Indeed, my Lord is encompassing of what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And O my people, work according to your position; indeed, I am working. You are going to know to whom will come a punishment that will disgrace him and who is a liar. So watch; indeed, I am with you a watcher, [awaiting the outcome]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when Our command came, We saved Shu''ayb and those who believed with him, by mercy from Us. And the shriek seized those who had wronged, and they became within their homes [corpses] fallen prone', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As if they had never prospered therein. Then, away with Madyan as Thamud was taken away.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did certainly send Moses with Our signs and a clear authority', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To Pharaoh and his establishment, but they followed the command of Pharaoh, and the command of Pharaoh was not [at all] discerning.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will precede his people on the Day of Resurrection and lead them into the Fire; and wretched is the place to which they are led.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they were followed in this [world] with a curse and on the Day of Resurrection. And wretched is the gift which is given.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is from the news of the cities, which We relate to you; of them, some are [still] standing and some are [as] a harvest [mowed down].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did not wrong them, but they wronged themselves. And they were not availed at all by their gods which they invoked other than Allah when there came the command of your Lord. And they did not increase them in other than ruin.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And thus is the seizure of your Lord when He seizes the cities while they are committing wrong. Indeed, His seizure is painful and severe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed in that is a sign for those who fear the punishment of the Hereafter. That is a Day for which the people will be collected, and that is a Day [which will be] witnessed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We do not delay it except for a limited term.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day it comes no soul will speak except by His permission. And among them will be the wretched and the prosperous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As for those who were [destined to be] wretched, they will be in the Fire. For them therein is [violent] exhaling and inhaling.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They will be] abiding therein as long as the heavens and the earth endure, except what your Lord should will. Indeed, your Lord is an effecter of what He intends.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And as for those who were [destined to be] prosperous, they will be in Paradise, abiding therein as long as the heavens and the earth endure, except what your Lord should will - a bestowal uninterrupted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So do not be in doubt, [O Muhammad], as to what these [polytheists] are worshipping. They worship not except as their fathers worshipped before. And indeed, We will give them their share undiminished.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had certainly given Moses the Scripture, but it came under disagreement. And if not for a word that preceded from your Lord, it would have been judged between them. And indeed they are, concerning the Qur''an, in disquieting doubt.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, each [of the believers and disbelievers] - your Lord will fully compensate them for their deeds. Indeed, He is Acquainted with what they do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 112), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So remain on a right course as you have been commanded, [you] and those who have turned back with you [to Allah], and do not transgress. Indeed, He is Seeing of what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 113), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not incline toward those who do wrong, lest you be touched by the Fire, and you would not have other than Allah any protectors; then you would not be helped.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 114), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And establish prayer at the two ends of the day and at the approach of the night. Indeed, good deeds do away with misdeeds. That is a reminder for those who remember.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 115), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And be patient, for indeed, Allah does not allow to be lost the reward of those who do good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 116), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So why were there not among the generations before you those of enduring discrimination forbidding corruption on earth - except a few of those We saved from among them? But those who wronged pursued what luxury they were given therein, and they were criminals.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 117), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your Lord would not have destroyed the cities unjustly while their people were reformers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 118), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if your Lord had willed, He could have made mankind one community; but they will not cease to differ.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 119), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except whom your Lord has given mercy, and for that He created them. But the word of your Lord is to be fulfilled that, "I will surely fill Hell with jinn and men all together."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 120), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And each [story] We relate to you from the news of the messengers is that by which We make firm your heart. And there has come to you, in this, the truth and an instruction and a reminder for the believers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 121), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And say to those who do not believe, "Work according to your position; indeed, we are working.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 122), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And wait, indeed, we are waiting."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 11 AND a.ayah_number = 123), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Allah belong the unseen [aspects] of the heavens and the earth and to Him will be returned the matter, all of it, so worship Him and rely upon Him. And your Lord is not unaware of that which you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Alif, Lam, Ra. These are the verses of the clear Book.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have sent it down as an Arabic Qur''an that you might understand.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We relate to you, [O Muhammad], the best of stories in what We have revealed to you of this Qur''an although you were, before it, among the unaware.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Of these stories mention] when Joseph said to his father, "O my father, indeed I have seen [in a dream] eleven stars and the sun and the moon; I saw them prostrating to me."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "O my son, do not relate your vision to your brothers or they will contrive against you a plan. Indeed Satan, to man, is a manifest enemy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And thus will your Lord choose you and teach you the interpretation of narratives and complete His favor upon you and upon the family of Jacob, as He completed it upon your fathers before, Abraham and Isaac. Indeed, your Lord is Knowing and Wise."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Certainly were there in Joseph and his brothers signs for those who ask,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When they said, "Joseph and his brother are more beloved to our father than we, while we are a clan. Indeed, our father is in clear error.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Kill Joseph or cast him out to [another] land; the countenance of your father will [then] be only for you, and you will be after that a righteous people."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Said a speaker among them, "Do not kill Joseph but throw him into the bottom of the well; some travelers will pick him up - if you would do [something]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "O our father, why do you not entrust us with Joseph while indeed, we are to him sincere counselors?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Send him with us tomorrow that he may eat well and play. And indeed, we will be his guardians.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Jacob] said, "Indeed, it saddens me that you should take him, and I fear that a wolf would eat him while you are of him unaware."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "If a wolf should eat him while we are a [strong] clan, indeed, we would then be losers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when they took him [out] and agreed to put him into the bottom of the well... But We inspired to him, "You will surely inform them [someday] about this affair of theirs while they do not perceive [your identity]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they came to their father at night, weeping.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "O our father, indeed we went racing each other and left Joseph with our possessions, and a wolf ate him. But you would not believe us, even if we were truthful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they brought upon his shirt false blood. [Jacob] said, "Rather, your souls have enticed you to something, so patience is most fitting. And Allah is the one sought for help against that which you describe."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there came a company of travelers; then they sent their water drawer, and he let down his bucket. He said, "Good news! Here is a boy." And they concealed him, [taking him] as merchandise; and Allah was knowing of what they did.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they sold him for a reduced price - a few dirhams - and they were, concerning him, of those content with little.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the one from Egypt who bought him said to his wife, "Make his residence comfortable. Perhaps he will benefit us, or we will adopt him as a son." And thus, We established Joseph in the land that We might teach him the interpretation of events. And Allah is predominant over His affair, but most of the people do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when Joseph reached maturity, We gave him judgment and knowledge. And thus We reward the doers of good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And she, in whose house he was, sought to seduce him. She closed the doors and said, "Come, you." He said, "[I seek] the refuge of Allah. Indeed, he is my master, who has made good my residence. Indeed, wrongdoers will not succeed."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And she certainly determined [to seduce] him, and he would have inclined to her had he not seen the proof of his Lord. And thus [it was] that We should avert from him evil and immorality. Indeed, he was of Our chosen servants.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they both raced to the door, and she tore his shirt from the back, and they found her husband at the door. She said, "What is the recompense of one who intended evil for your wife but that he be imprisoned or a painful punishment?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Joseph] said, "It was she who sought to seduce me." And a witness from her family testified. "If his shirt is torn from the front, then she has told the truth, and he is of the liars.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if his shirt is torn from the back, then she has lied, and he is of the truthful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when her husband saw his shirt torn from the back, he said, "Indeed, it is of the women''s plan. Indeed, your plan is great.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Joseph, ignore this. And, [my wife], ask forgiveness for your sin. Indeed, you were of the sinful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And women in the city said, "The wife of al-''Azeez is seeking to seduce her slave boy; he has impassioned her with love. Indeed, we see her [to be] in clear error."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when she heard of their scheming, she sent for them and prepared for them a banquet and gave each one of them a knife and said [to Joseph], "Come out before them." And when they saw him, they greatly admired him and cut their hands and said, "Perfect is Allah! This is not a man; this is none but a noble angel."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'She said, "That is the one about whom you blamed me. And I certainly sought to seduce him, but he firmly refused; and if he will not do what I order him, he will surely be imprisoned and will be of those debased."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "My Lord, prison is more to my liking than that to which they invite me. And if You do not avert from me their plan, I might incline toward them and [thus] be of the ignorant."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So his Lord responded to him and averted from him their plan. Indeed, He is the Hearing, the Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then it appeared to them after they had seen the signs that al-''Azeez should surely imprison him for a time.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there entered the prison with him two young men. One of them said, "Indeed, I have seen myself [in a dream] pressing wine." The other said, "Indeed, I have seen myself carrying upon my head [some] bread, from which the birds were eating. Inform us of its interpretation; indeed, we see you to be of those who do good."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "You will not receive food that is provided to you except that I will inform you of its interpretation before it comes to you. That is from what my Lord has taught me. Indeed, I have left the religion of a people who do not believe in Allah, and they, in the Hereafter, are disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And I have followed the religion of my fathers, Abraham, Isaac and Jacob. And it was not for us to associate anything with Allah. That is from the favor of Allah upon us and upon the people, but most of the people are not grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O [my] two companions of prison, are separate lords better or Allah, the One, the Prevailing?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You worship not besides Him except [mere] names you have named them, you and your fathers, for which Allah has sent down no authority. Legislation is not but for Allah. He has commanded that you worship not except Him. That is the correct religion, but most of the people do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O two companions of prison, as for one of you, he will give drink to his master of wine; but as for the other, he will be crucified, and the birds will eat from his head. The matter has been decreed about which you both inquire."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he said to the one whom he knew would go free, "Mention me before your master." But Satan made him forget the mention [to] his master, and Joseph remained in prison several years.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [subsequently] the king said, "Indeed, I have seen [in a dream] seven fat cows being eaten by seven [that were] lean, and seven green spikes [of grain] and others [that were] dry. O eminent ones, explain to me my vision, if you should interpret visions."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "[It is but] a mixture of false dreams, and we are not learned in the interpretation of dreams."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But the one who was freed and remembered after a time said, "I will inform you of its interpretation, so send me forth."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He said], "Joseph, O man of truth, explain to us about seven fat cows eaten by seven [that were] lean, and seven green spikes [of grain] and others [that were] dry - that I may return to the people; perhaps they will know [about you]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Joseph] said, "You will plant for seven years consecutively; and what you harvest leave in its spikes, except a little from which you will eat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then will come after that seven difficult [years] which will consume what you saved for them, except a little from which you will store.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then will come after that a year in which the people will be given rain and in which they will press [olives and grapes]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the king said, "Bring him to me." But when the messenger came to him, [Joseph] said, "Return to your master and ask him what is the case of the women who cut their hands. Indeed, my Lord is Knowing of their plan."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Said [the king to the women], "What was your condition when you sought to seduce Joseph?" They said, "Perfect is Allah! We know about him no evil." The wife of al-''Azeez said, "Now the truth has become evident. It was I who sought to seduce him, and indeed, he is of the truthful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is so al-''Azeez will know that I did not betray him in [his] absence and that Allah does not guide the plan of betrayers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And I do not acquit myself. Indeed, the soul is a persistent enjoiner of evil, except those upon which my Lord has mercy. Indeed, my Lord is Forgiving and Merciful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the king said, "Bring him to me; I will appoint him exclusively for myself." And when he spoke to him, he said, "Indeed, you are today established [in position] and trusted."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Joseph] said, "Appoint me over the storehouses of the land. Indeed, I will be a knowing guardian."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And thus We established Joseph in the land to settle therein wherever he willed. We touch with Our mercy whom We will, and We do not allow to be lost the reward of those who do good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the reward of the Hereafter is better for those who believed and were fearing Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the brothers of Joseph came [seeking food], and they entered upon him; and he recognized them, but he was to them unknown.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when he had furnished them with their supplies, he said, "Bring me a brother of yours from your father. Do not you see that I give full measure and that I am the best of accommodators?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if you do not bring him to me, no measure will there be [hereafter] for you from me, nor will you approach me."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "We will attempt to dissuade his father from [keeping] him, and indeed, we will do [it]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [Joseph] said to his servants, "Put their merchandise into their saddlebags so they might recognize it when they have gone back to their people that perhaps they will [again] return."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when they returned to their father, they said, "O our father, [further] measure has been denied to us, so send with us our brother [that] we will be given measure. And indeed, we will be his guardians."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "Should I entrust you with him except [under coercion] as I entrusted you with his brother before? But Allah is the best guardian, and He is the most merciful of the merciful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they opened their baggage, they found their merchandise returned to them. They said, "O our father, what [more] could we desire? This is our merchandise returned to us. And we will obtain supplies for our family and protect our brother and obtain an increase of a camel''s load; that is an easy measurement."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Jacob] said, "Never will I send him with you until you give me a promise by Allah that you will bring him [back] to me, unless you should be surrounded by enemies." And when they had given their promise, he said, "Allah, over what we say, is Witness."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he said, "O my sons, do not enter from one gate but enter from different gates; and I cannot avail you against [the decree of] Allah at all. The decision is only for Allah; upon Him I have relied, and upon Him let those who would rely [indeed] rely."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they entered from where their father had ordered them, it did not avail them against Allah at all except [it was] a need within the soul of Jacob, which he satisfied. And indeed, he was a possessor of knowledge because of what We had taught him, but most of the people do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they entered upon Joseph, he took his brother to himself; he said, "Indeed, I am your brother, so do not despair over what they used to do [to me]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when he had furnished them with their supplies, he put the [gold measuring] bowl into the bag of his brother. Then an announcer called out, "O caravan, indeed you are thieves."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said while approaching them, "What is it you are missing?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "We are missing the measure of the king. And for he who produces it is [the reward of] a camel''s load, and I am responsible for it."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "By Allah, you have certainly known that we did not come to cause corruption in the land, and we have not been thieves."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The accusers said, "Then what would be its recompense if you should be liars?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[The brothers] said, "Its recompense is that he in whose bag it is found - he [himself] will be its recompense. Thus do we recompense the wrongdoers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So he began [the search] with their bags before the bag of his brother; then he extracted it from the bag of his brother. Thus did We plan for Joseph. He could not have taken his brother within the religion of the king except that Allah willed. We raise in degrees whom We will, but over every possessor of knowledge is one [more] knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "If he steals - a brother of his has stolen before." But Joseph kept it within himself and did not reveal it to them. He said, "You are worse in position, and Allah is most knowing of what you describe."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "O ''Azeez, indeed he has a father [who is] an old man, so take one of us in place of him. Indeed, we see you as a doer of good."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "[I seek] the refuge of Allah [to prevent] that we take except him with whom we found our possession. Indeed, we would then be unjust."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when they had despaired of him, they secluded themselves in private consultation. The eldest of them said, "Do you not know that your father has taken upon you an oath by Allah and [that] before you failed in [your duty to] Joseph? So I will never leave [this] land until my father permits me or Allah decides for me, and He is the best of judges.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Return to your father and say, "O our father, indeed your son has stolen, and we did not testify except to what we knew. And we were not witnesses of the unseen,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And ask the city in which we were and the caravan in which we came - and indeed, we are truthful,"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Jacob] said, "Rather, your souls have enticed you to something, so patience is most fitting. Perhaps Allah will bring them to me all together. Indeed it is He who is the Knowing, the Wise."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he turned away from them and said, "Oh, my sorrow over Joseph," and his eyes became white from grief, for he was [of that] a suppressor.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "By Allah, you will not cease remembering Joseph until you become fatally ill or become of those who perish."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "I only complain of my suffering and my grief to Allah, and I know from Allah that which you do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O my sons, go and find out about Joseph and his brother and despair not of relief from Allah. Indeed, no one despairs of relief from Allah except the disbelieving people."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when they entered upon Joseph, they said, "O ''Azeez, adversity has touched us and our family, and we have come with goods poor in quality, but give us full measure and be charitable to us. Indeed, Allah rewards the charitable."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "Do you know what you did with Joseph and his brother when you were ignorant?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "Are you indeed Joseph?" He said "I am Joseph, and this is my brother. Allah has certainly favored us. Indeed, he who fears Allah and is patient, then indeed, Allah does not allow to be lost the reward of those who do good."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "By Allah, certainly has Allah preferred you over us, and indeed, we have been sinners."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "No blame will there be upon you today. Allah will forgive you; and He is the most merciful of the merciful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Take this, my shirt, and cast it over the face of my father; he will become seeing. And bring me your family, all together."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the caravan departed [from Egypt], their father said, "Indeed, I find the smell of Joseph [and would say that he was alive] if you did not think me weakened in mind."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "By Allah, indeed you are in your [same] old error."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the bearer of good tidings arrived, he cast it over his face, and he returned [once again] seeing. He said, "Did I not tell you that I know from Allah that which you do not know?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "O our father, ask for us forgiveness of our sins; indeed, we have been sinners."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "I will ask forgiveness for you from my Lord. Indeed, it is He who is the Forgiving, the Merciful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they entered upon Joseph, he took his parents to himself and said, "Enter Egypt, Allah willing, safe [and secure]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he raised his parents upon the throne, and they bowed to him in prostration. And he said, "O my father, this is the explanation of my vision of before. My Lord has made it reality. And He was certainly good to me when He took me out of prison and brought you [here] from bedouin life after Satan had induced [estrangement] between me and my brothers. Indeed, my Lord is Subtle in what He wills. Indeed, it is He who is the Knowing, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'My Lord, You have given me [something] of sovereignty and taught me of the interpretation of dreams. Creator of the heavens and earth, You are my protector in this world and in the Hereafter. Cause me to die a Muslim and join me with the righteous."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is from the news of the unseen which We reveal, [O Muhammad], to you. And you were not with them when they put together their plan while they conspired.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And most of the people, although you strive [for it], are not believers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you do not ask of them for it any payment. It is not except a reminder to the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And how many a sign within the heavens and earth do they pass over while they, therefrom, are turning away.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And most of them believe not in Allah except while they associate others with Him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then do they feel secure that there will not come to them an overwhelming [aspect] of the punishment of Allah or that the Hour will not come upon them suddenly while they do not perceive?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "This is my way; I invite to Allah with insight, I and those who follow me. And exalted is Allah; and I am not of those who associate others with Him."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We sent not before you [as messengers] except men to whom We revealed from among the people of cities. So have they not traveled through the earth and observed how was the end of those before them? And the home of the Hereafter is best for those who fear Allah; then will you not reason?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They continued] until, when the messengers despaired and were certain that they had been denied, there came to them Our victory, and whoever We willed was saved. And Our punishment cannot be repelled from the people who are criminals.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 12 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There was certainly in their stories a lesson for those of understanding. Never was the Qur''an a narration invented, but a confirmation of what was before it and a detailed explanation of all things and guidance and mercy for a people who believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Alif, Lam, Meem, Ra. These are the verses of the Book; and what has been revealed to you from your Lord is the truth, but most of the people do not believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is Allah who erected the heavens without pillars that you [can] see; then He established Himself above the Throne and made subject the sun and the moon, each running [its course] for a specified term. He arranges [each] matter; He details the signs that you may, of the meeting with your Lord, be certain.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is He who spread the earth and placed therein firmly set mountains and rivers; and from all of the fruits He made therein two mates; He causes the night to cover the day. Indeed in that are signs for a people who give thought.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And within the land are neighboring plots and gardens of grapevines and crops and palm trees, [growing] several from a root or otherwise, watered with one water; but We make some of them exceed others in [quality of] fruit. Indeed in that are signs for a people who reason.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you are astonished, [O Muhammad] - then astonishing is their saying, "When we are dust, will we indeed be [brought] into a new creation?" Those are the ones who have disbelieved in their Lord, and those will have shackles upon their necks, and those are the companions of the Fire; they will abide therein eternally.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They impatiently urge you to bring about evil before good, while there has already occurred before them similar punishments [to what they demand]. And indeed, your Lord is full of forgiveness for the people despite their wrongdoing, and indeed, your Lord is severe in penalty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who disbelieved say, "Why has a sign not been sent down to him from his Lord?" You are only a warner, and for every people is a guide.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah knows what every female carries and what the wombs lose [prematurely] or exceed. And everything with Him is by due measure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He is] Knower of the unseen and the witnessed, the Grand, the Exalted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is the same [to Him] concerning you whether one conceals [his] speech or one publicizes it and whether one is hidden by night or conspicuous [among others] by day.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For each one are successive [angels] before and behind him who protect him by the decree of Allah. Indeed, Allah will not change the condition of a people until they change what is in themselves. And when Allah intends for a people ill, there is no repelling it. And there is not for them besides Him any patron.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who shows you lightening, [causing] fear and aspiration, and generates the heavy clouds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the thunder exalts [Allah] with praise of Him - and the angels [as well] from fear of Him - and He sends thunderbolts and strikes therewith whom He wills while they dispute about Allah; and He is severe in assault.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To Him [alone] is the supplication of truth. And those they call upon besides Him do not respond to them with a thing, except as one who stretches his hands toward water [from afar, calling it] to reach his mouth, but it will not reach it [thus]. And the supplication of the disbelievers is not but in error [i.e. futility].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Allah prostrates whoever is within the heavens and the earth, willingly or by compulsion, and their shadows [as well] in the mornings and the afternoons.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Who is Lord of the heavens and earth?" Say, "Allah." Say, "Have you then taken besides Him allies not possessing [even] for themselves any benefit or any harm?" Say, "Is the blind equivalent to the seeing? Or is darkness equivalent to light? Or have they attributed to Allah partners who created like His creation so that the creation [of each] seemed similar to them?" Say, "Allah is the Creator of all things, and He is the One, the Prevailing."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He sends down from the sky, rain, and valleys flow according to their capacity, and the torrent carries a rising foam. And from that [ore] which they heat in the fire, desiring adornments and utensils, is a foam like it. Thus Allah presents [the example of] truth and falsehood. As for the foam, it vanishes, [being] cast off; but as for that which benefits the people, it remains on the earth. Thus does Allah present examples.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For those who have responded to their Lord is the best [reward], but those who did not respond to Him - if they had all that is in the earth entirely and the like of it with it, they would [attempt to] ransom themselves thereby. Those will have the worst account, and their refuge is Hell, and wretched is the resting place.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then is he who knows that what has been revealed to you from your Lord is the truth like one who is blind? They will only be reminded who are people of understanding -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who fulfill the covenant of Allah and do not break the contract,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who join that which Allah has ordered to be joined and fear their Lord and are afraid of the evil of [their] account,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who are patient, seeking the countenance of their Lord, and establish prayer and spend from what We have provided for them secretly and publicly and prevent evil with good - those will have the good consequence of [this] home -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Gardens of perpetual residence; they will enter them with whoever were righteous among their fathers, their spouses and their descendants. And the angels will enter upon them from every gate, [saying],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '"Peace be upon you for what you patiently endured. And excellent is the final home."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who break the covenant of Allah after contracting it and sever that which Allah has ordered to be joined and spread corruption on earth - for them is the curse, and they will have the worst home.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah extends provision for whom He wills and restricts [it]. And they rejoice in the worldly life, while the worldly life is not, compared to the Hereafter, except [brief] enjoyment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who disbelieved say, "Why has a sign not been sent down to him from his Lord?" Say, [O Muhammad], "Indeed, Allah leaves astray whom He wills and guides to Himself whoever turns back [to Him] -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who have believed and whose hearts are assured by the remembrance of Allah. Unquestionably, by the remembrance of Allah hearts are assured."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who have believed and done righteous deeds - a good state is theirs and a good return.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Thus have We sent you to a community before which [other] communities have passed on so you might recite to them that which We revealed to you, while they disbelieve in the Most Merciful. Say, "He is my Lord; there is no deity except Him. Upon Him I rely, and to Him is my return."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if there was any qur''an by which the mountains would be removed or the earth would be broken apart or the dead would be made to speak, [it would be this Qur''an], but to Allah belongs the affair entirely. Then have those who believed not accepted that had Allah willed, He would have guided the people, all of them? And those who disbelieve do not cease to be struck, for what they have done, by calamity - or it will descend near their home - until there comes the promise of Allah. Indeed, Allah does not fail in [His] promise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And already were [other] messengers ridiculed before you, and I extended the time of those who disbelieved; then I seized them, and how [terrible] was My penalty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then is He who is a maintainer of every soul, [knowing] what it has earned, [like any other]? But to Allah they have attributed partners. Say, "Name them. Or do you inform Him of that which He knows not upon the earth or of what is apparent of speech?" Rather, their [own] plan has been made attractive to those who disbelieve, and they have been averted from the way. And whomever Allah leaves astray - there will be for him no guide.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For them will be punishment in the life of [this] world, and the punishment of the Hereafter is more severe. And they will not have from Allah any protector.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The example of Paradise, which the righteous have been promised, is [that] beneath it rivers flow. Its fruit is lasting, and its shade. That is the consequence for the righteous, and the consequence for the disbelievers is the Fire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [the believers among] those to whom We have given the [previous] Scripture rejoice at what has been revealed to you, [O Muhammad], but among the [opposing] factions are those who deny part of it. Say, "I have only been commanded to worship Allah and not associate [anything] with Him. To Him I invite, and to Him is my return."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And thus We have revealed it as an Arabic legislation. And if you should follow their inclinations after what has come to you of knowledge, you would not have against Allah any ally or any protector.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have already sent messengers before you and assigned to them wives and descendants. And it was not for a messenger to come with a sign except by permission of Allah. For every term is a decree.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah eliminates what He wills or confirms, and with Him is the Mother of the Book.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whether We show you part of what We promise them or take you in death, upon you is only the [duty of] notification, and upon Us is the account.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have they not seen that We set upon the land, reducing it from its borders? And Allah decides; there is no adjuster of His decision. And He is swift in account.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those before them had plotted, but to Allah belongs the plan entirely. He knows what every soul earns, and the disbelievers will know for whom is the final home.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 13 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who have disbelieved say, "You are not a messenger." Say, [O Muhammad], "Sufficient is Allah as Witness between me and you, and [the witness of] whoever has knowledge of the Scripture."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Alif, Lam, Ra. [This is] a Book which We have revealed to you, [O Muhammad], that you might bring mankind out of darknesses into the light by permission of their Lord - to the path of the Exalted in Might, the Praiseworthy -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah, to whom belongs whatever is in the heavens and whatever is on the earth. And woe to the disbelievers from a severe punishment', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The ones who prefer the worldly life over the Hereafter and avert [people] from the way of Allah, seeking to make it (seem) deviant. Those are in extreme error.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did not send any messenger except [speaking] in the language of his people to state clearly for them, and Allah sends astray [thereby] whom He wills and guides whom He wills. And He is the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We certainly sent Moses with Our signs, [saying], "Bring out your people from darknesses into the light and remind them of the days of Allah." Indeed in that are signs for everyone patient and grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [recall, O Children of Israel], when Moses said to His people, "Remember the favor of Allah upon you when He saved you from the people of Pharaoh, who were afflicting you with the worst torment and were slaughtering your [newborn] sons and keeping your females alive. And in that was a great trial from your Lord.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [remember] when your Lord proclaimed, ''If you are grateful, I will surely increase you [in favor]; but if you deny, indeed, My punishment is severe.'' "', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Moses said, "If you should disbelieve, you and whoever is on the earth entirely - indeed, Allah is Free of need and Praiseworthy."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Has there not reached you the news of those before you - the people of Noah and ''Aad and Thamud and those after them? No one knows them but Allah. Their messengers brought them clear proofs, but they returned their hands to their mouths and said, "Indeed, we disbelieve in that with which you have been sent, and indeed we are, about that to which you invite us, in disquieting doubt."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their messengers said, "Can there be doubt about Allah, Creator of the heavens and earth? He invites you that He may forgive you of your sins, and He delays your death for a specified term." They said, "You are not but men like us who wish to avert us from what our fathers were worshipping. So bring us a clear authority."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their messengers said to them, "We are only men like you, but Allah confers favor upon whom He wills of His servants. It has never been for us to bring you evidence except by permission of Allah. And upon Allah let the believers rely.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And why should we not rely upon Allah while He has guided us to our [good] ways. And we will surely be patient against whatever harm you should cause us. And upon Allah let those who would rely [indeed] rely."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who disbelieved said to their messengers, "We will surely drive you out of our land, or you must return to our religion." So their Lord inspired to them, "We will surely destroy the wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We will surely cause you to dwell in the land after them. That is for he who fears My position and fears My threat."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they requested victory from Allah, and disappointed, [therefore], was every obstinate tyrant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Before him is Hell, and he will be given a drink of purulent water.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will gulp it but will hardly [be able to] swallow it. And death will come to him from everywhere, but he is not to die. And before him is a massive punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The example of those who disbelieve in their Lord is [that] their deeds are like ashes which the wind blows forcefully on a stormy day; they are unable [to keep] from what they earned a [single] thing. That is what is extreme error.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you not seen that Allah created the heavens and the earth in truth? If He wills, He can do away with you and produce a new creation.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that is not difficult for Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will come out [for judgement] before Allah all together, and the weak will say to those who were arrogant, "Indeed, we were your followers, so can you avail us anything against the punishment of Allah?" They will say, "If Allah had guided us, we would have guided you. It is all the same for us whether we show intolerance or are patient: there is for us no place of escape."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Satan will say when the matter has been concluded, "Indeed, Allah had promised you the promise of truth. And I promised you, but I betrayed you. But I had no authority over you except that I invited you, and you responded to me. So do not blame me; but blame yourselves. I cannot be called to your aid, nor can you be called to my aid. Indeed, I deny your association of me [with Allah] before. Indeed, for the wrongdoers is a painful punishment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who believed and did righteous deeds will be admitted to gardens beneath which rivers flow, abiding eternally therein by permission of their Lord; and their greeting therein will be, "Peace!"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you not considered how Allah presents an example, [making] a good word like a good tree, whose root is firmly fixed and its branches [high] in the sky?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It produces its fruit all the time, by permission of its Lord. And Allah presents examples for the people that perhaps they will be reminded.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the example of a bad word is like a bad tree, uprooted from the surface of the earth, not having any stability.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah keeps firm those who believe, with the firm word, in worldly life and in the Hereafter. And Allah sends astray the wrongdoers. And Allah does what He wills.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you not considered those who exchanged the favor of Allah for disbelief and settled their people [in] the home of ruin?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is] Hell, which they will [enter to] burn, and wretched is the settlement.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they have attributed to Allah equals to mislead [people] from His way. Say, "Enjoy yourselves, for indeed, your destination is the Fire."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[O Muhammad], tell My servants who have believed to establish prayer and spend from what We have provided them, secretly and publicly, before a Day comes in which there will be no exchange, nor any friendships.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is Allah who created the heavens and the earth and sent down rain from the sky and produced thereby some fruits as provision for you and subjected for you the ships to sail through the sea by His command and subjected for you the rivers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He subjected for you the sun and the moon, continuous [in orbit], and subjected for you the night and the day.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He gave you from all you asked of Him. And if you should count the favor of Allah, you could not enumerate them. Indeed, mankind is [generally] most unjust and ungrateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention, O Muhammad], when Abraham said, "My Lord, make this city [Makkah] secure and keep me and my sons away from worshipping idols.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'My Lord, indeed they have led astray many among the people. So whoever follows me - then he is of me; and whoever disobeys me - indeed, You are [yet] Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Our Lord, I have settled some of my descendants in an uncultivated valley near Your sacred House, our Lord, that they may establish prayer. So make hearts among the people incline toward them and provide for them from the fruits that they might be grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Our Lord, indeed You know what we conceal and what we declare, and nothing is hidden from Allah on the earth or in the heaven.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Praise to Allah, who has granted to me in old age Ishmael and Isaac. Indeed, my Lord is the Hearer of supplication.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'My Lord, make me an establisher of prayer, and [many] from my descendants. Our Lord, and accept my supplication.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Our Lord, forgive me and my parents and the believers the Day the account is established."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And never think that Allah is unaware of what the wrongdoers do. He only delays them for a Day when eyes will stare [in horror].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Racing ahead, their heads raised up, their glance does not come back to them, and their hearts are void.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And, [O Muhammad], warn the people of a Day when the punishment will come to them and those who did wrong will say, "Our Lord, delay us for a short term; we will answer Your call and follow the messengers." [But it will be said], "Had you not sworn, before, that for you there would be no cessation?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you lived among the dwellings of those who wronged themselves, and it had become clear to you how We dealt with them. And We presented for you [many] examples."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they had planned their plan, but with Allah is [recorded] their plan, even if their plan had been [sufficient] to do away with the mountains.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So never think that Allah will fail in His promise to His messengers. Indeed, Allah is Exalted in Might and Owner of Retribution.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It will be] on the Day the earth will be replaced by another earth, and the heavens [as well], and all creatures will come out before Allah, the One, the Prevailing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you will see the criminals that Day bound together in shackles,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their garments of liquid pitch and their faces covered by the Fire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So that Allah will recompense every soul for what it earned. Indeed, Allah is swift in account.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 14 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This [Qur''an] is notification for the people that they may be warned thereby and that they may know that He is but one God and that those of understanding will be reminded.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Alif, Lam, Ra. These are the verses of the Book and a clear Qur''an.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Perhaps those who disbelieve will wish that they had been Muslims.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Let them eat and enjoy themselves and be diverted by [false] hope, for they are going to know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did not destroy any city but that for it was a known decree.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No nation will precede its term, nor will they remain thereafter.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "O you upon whom the message has been sent down, indeed you are mad.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Why do you not bring us the angels, if you should be among the truthful?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We do not send down the angels except with truth; and the disbelievers would not then be reprieved.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, it is We who sent down the Qur''an and indeed, We will be its guardian.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had certainly sent [messengers] before you, [O Muhammad], among the sects of the former peoples.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And no messenger would come to them except that they ridiculed him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Thus do We insert denial into the hearts of the criminals.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will not believe in it, while there has already occurred the precedent of the former peoples.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [even] if We opened to them a gate from the heaven and they continued therein to ascend,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They would say, "Our eyes have only been dazzled. Rather, we are a people affected by magic."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have placed within the heaven great stars and have beautified it for the observers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have protected it from every devil expelled [from the mercy of Allah]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except one who steals a hearing and is pursued by a clear burning flame.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the earth - We have spread it and cast therein firmly set mountains and caused to grow therein [something] of every well-balanced thing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have made for you therein means of living and [for] those for whom you are not providers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there is not a thing but that with Us are its depositories, and We do not send it down except according to a known measure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have sent the fertilizing winds and sent down water from the sky and given you drink from it. And you are not its retainers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, it is We who give life and cause death, and We are the Inheritor.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have already known the preceding [generations] among you, and We have already known the later [ones to come].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, your Lord will gather them; indeed, He is Wise and Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did certainly create man out of clay from an altered black mud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the jinn We created before from scorching fire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention, O Muhammad], when your Lord said to the angels, "I will create a human being out of clay from an altered black mud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when I have proportioned him and breathed into him of My [created] soul, then fall down to him in prostration."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So the angels prostrated - all of them entirely,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except Iblees, he refused to be with those who prostrated.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah] said, O Iblees, what is [the matter] with you that you are not with those who prostrate?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "Never would I prostrate to a human whom You created out of clay from an altered black mud."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah] said, "Then get out of it, for indeed, you are expelled.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, upon you is the curse until the Day of Recompense."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "My Lord, then reprieve me until the Day they are resurrected."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah] said, "So indeed, you are of those reprieved', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Until the Day of the time well-known."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Iblees] said, "My Lord, because You have put me in error, I will surely make [disobedience] attractive to them on earth, and I will mislead them all', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except, among them, Your chosen servants."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah] said, "This is a path [of return] to Me [that is] straight.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, My servants - no authority will you have over them, except those who follow you of the deviators.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, Hell is the promised place for them all.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It has seven gates; for every gate is of them a portion designated."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the righteous will be within gardens and springs.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Having been told], "Enter it in peace, safe [and secure]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We will remove whatever is in their breasts of resentment, [so they will be] brothers, on thrones facing each other.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No fatigue will touch them therein, nor from it will they [ever] be removed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[O Muhammad], inform My servants that it is I who am the Forgiving, the Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that it is My punishment which is the painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And inform them about the guests of Abraham,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When they entered upon him and said, "Peace." [Abraham] said, "Indeed, we are fearful of you."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[The angels] said, "Fear not. Indeed, we give you good tidings of a learned boy."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "Have you given me good tidings although old age has come upon me? Then of what [wonder] do you inform?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "We have given you good tidings in truth, so do not be of the despairing."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "And who despairs of the mercy of his Lord except for those astray?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Abraham] said, "Then what is your business [here], O messengers?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "Indeed, we have been sent to a people of criminals,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except the family of Lot; indeed, we will save them all', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except his wife." Allah decreed that she is of those who remain behind.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the messengers came to the family of Lot,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "Indeed, you are people unknown."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "But we have come to you with that about which they were disputing,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we have come to you with truth, and indeed, we are truthful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So set out with your family during a portion of the night and follow behind them and let not anyone among you look back and continue on to where you are commanded."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We conveyed to him [the decree] of that matter: that those [sinners] would be eliminated by early morning.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the people of the city came rejoicing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Lot] said, "Indeed, these are my guests, so do not shame me.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And fear Allah and do not disgrace me."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "Have we not forbidden you from [protecting] people?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Lot] said, "These are my daughters - if you would be doers [of lawful marriage]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By your life, [O Muhammad], indeed they were, in their intoxication, wandering blindly.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So the shriek seized them at sunrise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We made the highest part [of the city] its lowest and rained upon them stones of hard clay.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed in that are signs for those who discern.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, those cities are [situated] on an established road.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed in that is a sign for the believers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the companions of the thicket were [also] wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So We took retribution from them, and indeed, both [cities] are on a clear highway.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And certainly did the companions of Thamud deny the messengers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We gave them Our signs, but from them they were turning away.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they used to carve from the mountains, houses, feeling secure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But the shriek seized them at early morning.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So nothing availed them [from] what they used to earn.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have not created the heavens and earth and that between them except in truth. And indeed, the Hour is coming; so forgive with gracious forgiveness.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, your Lord - He is the Knowing Creator.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have certainly given you, [O Muhammad], seven of the often repeated [verses] and the great Qur''an.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do not extend your eyes toward that by which We have given enjoyment to [certain] categories of the disbelievers, and do not grieve over them. And lower your wing to the believers', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And say, "Indeed, I am the clear warner" -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Just as We had revealed [scriptures] to the separators', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who have made the Qur''an into portions.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So by your Lord, We will surely question them all', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'About what they used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then declare what you are commanded and turn away from the polytheists.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We are sufficient for you against the mockers', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who make [equal] with Allah another deity. But they are going to know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We already know that your breast is constrained by what they say.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So exalt [Allah] with praise of your Lord and be of those who prostrate [to Him].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 15 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And worship your Lord until there comes to you the certainty (death).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The command of Allah is coming, so be not impatient for it. Exalted is He and high above what they associate with Him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He sends down the angels, with the inspiration of His command, upon whom He wills of His servants, [telling them], "Warn that there is no deity except Me; so fear Me."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He created the heavens and earth in truth. High is He above what they associate with Him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He created man from a sperm-drop; then at once, he is a clear adversary.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the grazing livestock He has created for you; in them is warmth and [numerous] benefits, and from them you eat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And for you in them is [the enjoyment of] beauty when you bring them in [for the evening] and when you send them out [to pasture].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they carry your loads to a land you could not have reached except with difficulty to yourselves. Indeed, your Lord is Kind and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [He created] the horses, mules and donkeys for you to ride and [as] adornment. And He creates that which you do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And upon Allah is the direction of the [right] way, and among the various paths are those deviating. And if He willed, He could have guided you all.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who sends down rain from the sky; from it is drink and from it is foliage in which you pasture [animals].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He causes to grow for you thereby the crops, olives, palm trees, grapevines, and from all the fruits. Indeed in that is a sign for a people who give thought.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He has subjected for you the night and day and the sun and moon, and the stars are subjected by His command. Indeed in that are signs for a people who reason.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [He has subjected] whatever He multiplied for you on the earth of varying colors. Indeed in that is a sign for a people who remember.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is He who subjected the sea for you to eat from it tender meat and to extract from it ornaments which you wear. And you see the ships plowing through it, and [He subjected it] that you may seek of His bounty; and perhaps you will be grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He has cast into the earth firmly set mountains, lest it shift with you, and [made] rivers and roads, that you may be guided,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And landmarks. And by the stars they are [also] guided.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then is He who creates like one who does not create? So will you not be reminded?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you should count the favors of Allah, you could not enumerate them. Indeed, Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah knows what you conceal and what you declare.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those they invoke other than Allah create nothing, and they [themselves] are created.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They are, [in fact], dead, not alive, and they do not perceive when they will be resurrected.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Your god is one God. But those who do not believe in the Hereafter - their hearts are disapproving, and they are arrogant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Assuredly, Allah knows what they conceal and what they declare. Indeed, He does not like the arrogant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when it is said to them, "What has your Lord sent down?" They say, "Legends of the former peoples,"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That they may bear their own burdens in full on the Day of Resurrection and some of the burdens of those whom they misguide without knowledge. Unquestionably, evil is that which they bear.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those before them had already plotted, but Allah came at their building from the foundations, so the roof fell upon them from above them, and the punishment came to them from where they did not perceive.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then on the Day of Resurrection He will disgrace them and say, "Where are My ''partners'' for whom you used to oppose [the believers]?" Those who were given knowledge will say, "Indeed disgrace, this Day, and evil are upon the disbelievers" -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The ones whom the angels take in death [while] wronging themselves, and [who] then offer submission, [saying], "We were not doing any evil." But, yes! Indeed, Allah is Knowing of what you used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So enter the gates of Hell to abide eternally therein, and how wretched is the residence of the arrogant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it will be said to those who feared Allah, "What did your Lord send down?" They will say, "[That which is] good." For those who do good in this world is good; and the home of the Hereafter is better. And how excellent is the home of the righteous -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Gardens of perpetual residence, which they will enter, beneath which rivers flow. They will have therein whatever they wish. Thus does Allah reward the righteous -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The ones whom the angels take in death, [being] good and pure; [the angels] will say, "Peace be upon you. Enter Paradise for what you used to do."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do the disbelievers await [anything] except that the angels should come to them or there comes the command of your Lord? Thus did those do before them. And Allah wronged them not, but they had been wronging themselves.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So they were struck by the evil consequences of what they did and were enveloped by what they used to ridicule.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who associate others with Allah say, "If Allah had willed, we would not have worshipped anything other than Him, neither we nor our fathers, nor would we have forbidden anything through other than Him." Thus did those do before them. So is there upon the messengers except [the duty of] clear notification?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We certainly sent into every nation a messenger, [saying], "Worship Allah and avoid Taghut." And among them were those whom Allah guided, and among them were those upon whom error was [deservedly] decreed. So proceed through the earth and observe how was the end of the deniers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Even] if you should strive for their guidance, [O Muhammad], indeed, Allah does not guide those He sends astray, and they will have no helpers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they swear by Allah their strongest oaths [that] Allah will not resurrect one who dies. But yes - [it is] a true promise [binding] upon Him, but most of the people do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is] so He will make clear to them [the truth of] that wherein they differ and so those who have disbelieved may know that they were liars.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Our word to a thing when We intend it is but that We say to it, "Be," and it is.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who emigrated for [the cause of] Allah after they had been wronged - We will surely settle them in this world in a good place; but the reward of the Hereafter is greater, if only they could know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They are] those who endured patiently and upon their Lord relied.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We sent not before you except men to whom We revealed [Our message]. So ask the people of the message if you do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[We sent them] with clear proofs and written ordinances. And We revealed to you the message that you may make clear to the people what was sent down to them and that they might give thought.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then, do those who have planned evil deeds feel secure that Allah will not cause the earth to swallow them or that the punishment will not come upon them from where they do not perceive?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or that He would not seize them during their [usual] activity, and they could not cause failure?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or that He would not seize them gradually [in a state of dread]? But indeed, your Lord is Kind and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have they not considered what things Allah has created? Their shadows incline to the right and to the left, prostrating to Allah, while they are humble.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Allah prostrates whatever is in the heavens and whatever is on the earth of creatures, and the angels [as well], and they are not arrogant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They fear their Lord above them, and they do what they are commanded.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah has said, "Do not take for yourselves two deities. He is but one God, so fear only Me."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Him belongs whatever is in the heavens and the earth, and to Him is [due] worship constantly. Then is it other than Allah that you fear?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whatever you have of favor - it is from Allah. Then when adversity touches you, to Him you cry for help.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then when He removes the adversity from you, at once a party of you associates others with their Lord', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So they will deny what We have given them. Then enjoy yourselves, for you are going to know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they assign to what they do not know a portion of that which We have provided them. By Allah, you will surely be questioned about what you used to invent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they attribute to Allah daughters - exalted is He - and for them is what they desire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when one of them is informed of [the birth of] a female, his face becomes dark, and he suppresses grief.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He hides himself from the people because of the ill of which he has been informed. Should he keep it in humiliation or bury it in the ground? Unquestionably, evil is what they decide.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For those who do not believe in the Hereafter is the description of evil; and for Allah is the highest attribute. And He is Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if Allah were to impose blame on the people for their wrongdoing, He would not have left upon the earth any creature, but He defers them for a specified term. And when their term has come, they will not remain behind an hour, nor will they precede [it].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they attribute to Allah that which they dislike, and their tongues assert the lie that they will have the best [from Him]. Assuredly, they will have the Fire, and they will be [therein] neglected.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By Allah, We did certainly send [messengers] to nations before you, but Satan made their deeds attractive to them. And he is the disbelievers'' ally today [as well], and they will have a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have not revealed to you the Book, [O Muhammad], except for you to make clear to them that wherein they have differed and as guidance and mercy for a people who believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah has sent down rain from the sky and given life thereby to the earth after its lifelessness. Indeed in that is a sign for a people who listen.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, for you in grazing livestock is a lesson. We give you drink from what is in their bellies - between excretion and blood - pure milk, palatable to drinkers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And from the fruits of the palm trees and grapevines you take intoxicant and good provision. Indeed in that is a sign for a people who reason.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your Lord inspired to the bee, "Take for yourself among the mountains, houses, and among the trees and [in] that which they construct.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then eat from all the fruits and follow the ways of your Lord laid down [for you]." There emerges from their bellies a drink, varying in colors, in which there is healing for people. Indeed in that is a sign for a people who give thought.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah created you; then He will take you in death. And among you is he who is reversed to the most decrepit [old] age so that he will not know, after [having had] knowledge, a thing. Indeed, Allah is Knowing and Competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah has favored some of you over others in provision. But those who were favored would not hand over their provision to those whom their right hands possess so they would be equal to them therein. Then is it the favor of Allah they reject?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah has made for you from yourselves mates and has made for you from your mates sons and grandchildren and has provided for you from the good things. Then in falsehood do they believe and in the favor of Allah they disbelieve?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they worship besides Allah that which does not possess for them [the power of] provision from the heavens and the earth at all, and [in fact], they are unable.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So do not assert similarities to Allah. Indeed, Allah knows and you do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah presents an example: a slave [who is] owned and unable to do a thing and he to whom We have provided from Us good provision, so he spends from it secretly and publicly. Can they be equal? Praise to Allah! But most of them do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah presents an example of two men, one of them dumb and unable to do a thing, while he is a burden to his guardian. Wherever he directs him, he brings no good. Is he equal to one who commands justice, while he is on a straight path?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Allah belongs the unseen [aspects] of the heavens and the earth. And the command for the Hour is not but as a glance of the eye or even nearer. Indeed, Allah is over all things competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah has extracted you from the wombs of your mothers not knowing a thing, and He made for you hearing and vision and intellect that perhaps you would be grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they not see the birds controlled in the atmosphere of the sky? None holds them up except Allah. Indeed in that are signs for a people who believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah has made for you from your homes a place of rest and made for you from the hides of the animals tents which you find light on your day of travel and your day of encampment; and from their wool, fur and hair is furnishing and enjoyment for a time.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah has made for you, from that which He has created, shadows and has made for you from the mountains, shelters and has made for you garments which protect you from the heat and garments which protect you from your [enemy in] battle. Thus does He complete His favor upon you that you might submit [to Him].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if they turn away, [O Muhammad] - then only upon you is [responsibility for] clear notification.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They recognize the favor of Allah; then they deny it. And most of them are disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention] the Day when We will resurrect from every nation a witness. Then it will not be permitted to the disbelievers [to apologize or make excuses], nor will they be asked to appease [Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when those who wronged see the punishment, it will not be lightened for them, nor will they be reprieved.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when those who associated others with Allah see their "partners," they will say," Our Lord, these are our partners [to You] whom we used to invoke besides You." But they will throw at them the statement, "Indeed, you are liars."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will impart to Allah that Day [their] submission, and lost from them is what they used to invent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who disbelieved and averted [others] from the way of Allah - We will increase them in punishment over [their] punishment for what corruption they were causing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention] the Day when We will resurrect among every nation a witness over them from themselves. And We will bring you, [O Muhammad], as a witness over your nation. And We have sent down to you the Book as clarification for all things and as guidance and mercy and good tidings for the Muslims.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah orders justice and good conduct and giving to relatives and forbids immorality and bad conduct and oppression. He admonishes you that perhaps you will be reminded.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And fulfill the covenant of Allah when you have taken it, [O believers], and do not break oaths after their confirmation while you have made Allah, over you, a witness. Indeed, Allah knows what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not be like she who untwisted her spun thread after it was strong [by] taking your oaths as [means of] deceit between you because one community is more plentiful [in number or wealth] than another community. Allah only tries you thereby. And He will surely make clear to you on the Day of Resurrection that over which you used to differ.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if Allah had willed, He could have made you [of] one religion, but He causes to stray whom He wills and guides whom He wills. And you will surely be questioned about what you used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not take your oaths as [means of] deceit between you, lest a foot slip after it was [once] firm, and you would taste evil [in this world] for what [people] you diverted from the way of Allah, and you would have [in the Hereafter] a great punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not exchange the covenant of Allah for a small price. Indeed, what is with Allah is best for you, if only you could know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whatever you have will end, but what Allah has is lasting. And We will surely give those who were patient their reward according to the best of what they used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever does righteousness, whether male or female, while he is a believer - We will surely cause him to live a good life, and We will surely give them their reward [in the Hereafter] according to the best of what they used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when you recite the Qur''an, [first] seek refuge in Allah from Satan, the expelled [from His mercy].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, there is for him no authority over those who have believed and rely upon their Lord.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'His authority is only over those who take him as an ally and those who through him associate others with Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when We substitute a verse in place of a verse - and Allah is most knowing of what He sends down - they say, "You, [O Muhammad], are but an inventor [of lies]." But most of them do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "The Pure Spirit has brought it down from your Lord in truth to make firm those who believe and as guidance and good tidings to the Muslims."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We certainly know that they say, "It is only a human being who teaches the Prophet." The tongue of the one they refer to is foreign, and this Qur''an is [in] a clear Arabic language.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who do not believe in the verses of Allah - Allah will not guide them, and for them is a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They only invent falsehood who do not believe in the verses of Allah, and it is those who are the liars.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever disbelieves in Allah after his belief... except for one who is forced [to renounce his religion] while his heart is secure in faith. But those who [willingly] open their breasts to disbelief, upon them is wrath from Allah, and for them is a great punishment;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is because they preferred the worldly life over the Hereafter and that Allah does not guide the disbelieving people.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those are the ones over whose hearts and hearing and vision Allah has sealed, and it is those who are the heedless.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Assuredly, it is they, in the Hereafter, who will be the losers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then, indeed your Lord, to those who emigrated after they had been compelled [to renounce their religion] and thereafter fought [for the cause of Allah] and were patient - indeed, your Lord, after that, is Forgiving and Merciful', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On the Day when every soul will come disputing for itself, and every soul will be fully compensated for what it did, and they will not be wronged.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 112), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah presents an example: a city which was safe and secure, its provision coming to it in abundance from every location, but it denied the favors of Allah. So Allah made it taste the envelopment of hunger and fear for what they had been doing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 113), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there had certainly come to them a Messenger from among themselves, but they denied him; so punishment overtook them while they were wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 114), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then eat of what Allah has provided for you [which is] lawful and good. And be grateful for the favor of Allah, if it is [indeed] Him that you worship.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 115), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He has only forbidden to you dead animals, blood, the flesh of swine, and that which has been dedicated to other than Allah. But whoever is forced [by necessity], neither desiring [it] nor transgressing [its limit] - then indeed, Allah is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 116), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not say about what your tongues assert of untruth, "This is lawful and this is unlawful," to invent falsehood about Allah. Indeed, those who invent falsehood about Allah will not succeed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 117), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is but] a brief enjoyment, and they will have a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 118), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to those who are Jews We have prohibited that which We related to you before. And We did not wrong them [thereby], but they were wronging themselves.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 119), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then, indeed your Lord, to those who have done wrong out of ignorance and then repent after that and correct themselves - indeed, your Lord, thereafter, is Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 120), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Abraham was a [comprehensive] leader, devoutly obedient to Allah, inclining toward truth, and he was not of those who associate others with Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 121), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He was] grateful for His favors. Allah chose him and guided him to a straight path.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 122), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We gave him good in this world, and indeed, in the Hereafter he will be among the righteous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 123), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We revealed to you, [O Muhammad], to follow the religion of Abraham, inclining toward truth; and he was not of those who associate with Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 124), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The sabbath was only appointed for those who differed over it. And indeed, your Lord will judge between them on the Day of Resurrection concerning that over which they used to differ.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 125), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Invite to the way of your Lord with wisdom and good instruction, and argue with them in a way that is best. Indeed, your Lord is most knowing of who has strayed from His way, and He is most knowing of who is [rightly] guided.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 126), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you punish [an enemy, O believers], punish with an equivalent of that with which you were harmed. But if you are patient - it is better for those who are patient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 127), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And be patient, [O Muhammad], and your patience is not but through Allah. And do not grieve over them and do not be in distress over what they conspire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 16 AND a.ayah_number = 128), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah is with those who fear Him and those who are doers of good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Exalted is He who took His Servant by night from al-Masjid al-Haram to al-Masjid al-Aqsa, whose surroundings We have blessed, to show him of Our signs. Indeed, He is the Hearing, the Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We gave Moses the Scripture and made it a guidance for the Children of Israel that you not take other than Me as Disposer of affairs,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O descendants of those We carried [in the ship] with Noah. Indeed, he was a grateful servant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We conveyed to the Children of Israel in the Scripture that, "You will surely cause corruption on the earth twice, and you will surely reach [a degree of] great haughtiness.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when the [time of] promise came for the first of them, We sent against you servants of Ours - those of great military might, and they probed [even] into the homes, and it was a promise fulfilled.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We gave back to you a return victory over them. And We reinforced you with wealth and sons and made you more numerous in manpower', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[And said], "If you do good, you do good for yourselves; and if you do evil, [you do it] to yourselves." Then when the final promise came, [We sent your enemies] to sadden your faces and to enter the temple in Jerusalem, as they entered it the first time, and to destroy what they had taken over with [total] destruction.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Then Allah said], "It is expected, [if you repent], that your Lord will have mercy upon you. But if you return [to sin], We will return [to punishment]. And We have made Hell, for the disbelievers, a prison-bed."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, this Qur''an guides to that which is most suitable and gives good tidings to the believers who do righteous deeds that they will have a great reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that those who do not believe in the Hereafter - We have prepared for them a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And man supplicates for evil as he supplicates for good, and man is ever hasty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have made the night and day two signs, and We erased the sign of the night and made the sign of the day visible that you may seek bounty from your Lord and may know the number of years and the account [of time]. And everything We have set out in detail.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [for] every person We have imposed his fate upon his neck, and We will produce for him on the Day of Resurrection a record which he will encounter spread open.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It will be said], "Read your record. Sufficient is yourself against you this Day as accountant."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever is guided is only guided for [the benefit of] his soul. And whoever errs only errs against it. And no bearer of burdens will bear the burden of another. And never would We punish until We sent a messenger.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when We intend to destroy a city, We command its affluent but they defiantly disobey therein; so the word comes into effect upon it, and We destroy it with [complete] destruction.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And how many have We destroyed from the generations after Noah. And sufficient is your Lord, concerning the sins of His servants, as Acquainted and Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever should desire the immediate - We hasten for him from it what We will to whom We intend. Then We have made for him Hell, which he will [enter to] burn, censured and banished.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But whoever desires the Hereafter and exerts the effort due to it while he is a believer - it is those whose effort is ever appreciated [by Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To each [category] We extend - to these and to those - from the gift of your Lord. And never has the gift of your Lord been restricted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Look how We have favored [in provision] some of them over others. But the Hereafter is greater in degrees [of difference] and greater in distinction.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do not make [as equal] with Allah another deity and [thereby] become censured and forsaken.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your Lord has decreed that you not worship except Him, and to parents, good treatment. Whether one or both of them reach old age [while] with you, say not to them [so much as], "uff," and do not repel them but speak to them a noble word.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And lower to them the wing of humility out of mercy and say, "My Lord, have mercy upon them as they brought me up [when I was] small."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Your Lord is most knowing of what is within yourselves. If you should be righteous [in intention] - then indeed He is ever, to the often returning [to Him], Forgiving.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And give the relative his right, and [also] the poor and the traveler, and do not spend wastefully.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the wasteful are brothers of the devils, and ever has Satan been to his Lord ungrateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you [must] turn away from the needy awaiting mercy from your Lord which you expect, then speak to them a gentle word.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not make your hand [as] chained to your neck or extend it completely and [thereby] become blamed and insolvent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, your Lord extends provision for whom He wills and restricts [it]. Indeed He is ever, concerning His servants, Acquainted and Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not kill your children for fear of poverty. We provide for them and for you. Indeed, their killing is ever a great sin.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not approach unlawful sexual intercourse. Indeed, it is ever an immorality and is evil as a way.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not kill the soul which Allah has forbidden, except by right. And whoever is killed unjustly - We have given his heir authority, but let him not exceed limits in [the matter of] taking life. Indeed, he has been supported [by the law].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not approach the property of an orphan, except in the way that is best, until he reaches maturity. And fulfill [every] commitment. Indeed, the commitment is ever [that about which one will be] questioned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And give full measure when you measure, and weigh with an even balance. That is the best [way] and best in result.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not pursue that of which you have no knowledge. Indeed, the hearing, the sight and the heart - about all those [one] will be questioned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not walk upon the earth exultantly. Indeed, you will never tear the earth [apart], and you will never reach the mountains in height.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'All that - its evil is ever, in the sight of your Lord, detested.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is from what your Lord has revealed to you, [O Muhammad], of wisdom. And, [O mankind], do not make [as equal] with Allah another deity, lest you be thrown into Hell, blamed and banished.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then, has your Lord chosen you for [having] sons and taken from among the angels daughters? Indeed, you say a grave saying.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have certainly diversified [the contents] in this Qur''an that mankind may be reminded, but it does not increase the disbelievers except in aversion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "If there had been with Him [other] gods, as they say, then they [each] would have sought to the Owner of the Throne a way."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Exalted is He and high above what they say by great sublimity.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The seven heavens and the earth and whatever is in them exalt Him. And there is not a thing except that it exalts [Allah] by His praise, but you do not understand their [way of] exalting. Indeed, He is ever Forbearing and Forgiving.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when you recite the Qur''an, We put between you and those who do not believe in the Hereafter a concealed partition.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have placed over their hearts coverings, lest they understand it, and in their ears deafness. And when you mention your Lord alone in the Qur''an, they turn back in aversion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We are most knowing of how they listen to it when they listen to you and [of] when they are in private conversation, when the wrongdoers say, "You follow not but a man affected by magic."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Look how they strike for you comparisons; but they have strayed, so they cannot [find] a way.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "When we are bones and crumbled particles, will we [truly] be resurrected as a new creation?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Be you stones or iron', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or [any] creation of that which is great within your breasts." And they will say, "Who will restore us?" Say, "He who brought you forth the first time." Then they will nod their heads toward you and say, "When is that?" Say, "Perhaps it will be soon -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On the Day He will call you and you will respond with praise of Him and think that you had not remained [in the world] except for a little."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And tell My servants to say that which is best. Indeed, Satan induces [dissension] among them. Indeed Satan is ever, to mankind, a clear enemy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Your Lord is most knowing of you. If He wills, He will have mercy upon you; or if He wills, He will punish you. And We have not sent you, [O Muhammad], over them as a manager.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your Lord is most knowing of whoever is in the heavens and the earth. And We have made some of the prophets exceed others [in various ways], and to David We gave the book [of Psalms].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Invoke those you have claimed [as gods] besides Him, for they do not possess the [ability for] removal of adversity from you or [for its] transfer [to someone else]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those whom they invoke seek means of access to their Lord, [striving as to] which of them would be nearest, and they hope for His mercy and fear His punishment. Indeed, the punishment of your Lord is ever feared.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there is no city but that We will destroy it before the Day of Resurrection or punish it with a severe punishment. That has ever been in the Register inscribed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And nothing has prevented Us from sending signs except that the former peoples denied them. And We gave Thamud the she-camel as a visible sign, but they wronged her. And We send not the signs except as a warning.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [remember, O Muhammad], when We told you, "Indeed, your Lord has encompassed the people." And We did not make the sight which We showed you except as a trial for the people, as was the accursed tree [mentioned] in the Qur''an. And We threaten them, but it increases them not except in great transgression.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention] when We said to the angles, "Prostrate to Adam," and they prostrated, except for Iblees. He said, "Should I prostrate to one You created from clay?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Iblees] said, "Do You see this one whom You have honored above me? If You delay me until the Day of Resurrection, I will surely destroy his descendants, except for a few."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah] said, "Go, for whoever of them follows you, indeed Hell will be the recompense of you - an ample recompense.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And incite [to senselessness] whoever you can among them with your voice and assault them with your horses and foot soldiers and become a partner in their wealth and their children and promise them." But Satan does not promise them except delusion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, over My [believing] servants there is for you no authority. And sufficient is your Lord as Disposer of affairs.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is your Lord who drives the ship for you through the sea that you may seek of His bounty. Indeed, He is ever, to you, Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when adversity touches you at sea, lost are [all] those you invoke except for Him. But when He delivers you to the land, you turn away [from Him]. And ever is man ungrateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then do you feel secure that [instead] He will not cause a part of the land to swallow you or send against you a storm of stones? Then you would not find for yourselves an advocate.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do you feel secure that He will not send you back into the sea another time and send upon you a hurricane of wind and drown you for what you denied? Then you would not find for yourselves against Us an avenger.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have certainly honored the children of Adam and carried them on the land and sea and provided for them of the good things and preferred them over much of what We have created, with [definite] preference.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Mention, O Muhammad], the Day We will call forth every people with their record [of deeds]. Then whoever is given his record in his right hand - those will read their records, and injustice will not be done to them, [even] as much as a thread [inside the date seed].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever is blind in this [life] will be blind in the Hereafter and more astray in way.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, they were about to tempt you away from that which We revealed to you in order to [make] you invent about Us something else; and then they would have taken you as a friend.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We had not strengthened you, you would have almost inclined to them a little.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then [if you had], We would have made you taste double [punishment in] life and double [after] death. Then you would not find for yourself against Us a helper.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, they were about to drive you from the land to evict you therefrom. And then [when they do], they will not remain [there] after you, except for a little.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[That is Our] established way for those We had sent before you of Our messengers; and you will not find in Our way any alteration.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Establish prayer at the decline of the sun [from its meridian] until the darkness of the night and [also] the Qur''an of dawn. Indeed, the recitation of dawn is ever witnessed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And from [part of] the night, pray with it as additional [worship] for you; it is expected that your Lord will resurrect you to a praised station.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And say, "My Lord, cause me to enter a sound entrance and to exit a sound exit and grant me from Yourself a supporting authority."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And say, "Truth has come, and falsehood has departed. Indeed is falsehood, [by nature], ever bound to depart."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We send down of the Qur''an that which is healing and mercy for the believers, but it does not increase the wrongdoers except in loss.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when We bestow favor upon the disbeliever, he turns away and distances himself; and when evil touches him, he is ever despairing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Each works according to his manner, but your Lord is most knowing of who is best guided in way."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they ask you, [O Muhammad], about the soul. Say, "The soul is of the affair of my Lord. And mankind have not been given of knowledge except a little."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We willed, We could surely do away with that which We revealed to you. Then you would not find for yourself concerning it an advocate against Us.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except [We have left it with you] as a mercy from your Lord. Indeed, His favor upon you has ever been great.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "If mankind and the jinn gathered in order to produce the like of this Qur''an, they could not produce the like of it, even if they were to each other assistants."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have certainly diversified for the people in this Qur''an from every [kind] of example, but most of the people refused [anything] except disbelief.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "We will not believe you until you break open for us from the ground a spring.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or [until] you have a garden of palm tress and grapes and make rivers gush forth within them in force [and abundance]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or you make the heaven fall upon us in fragments as you have claimed or you bring Allah and the angels before [us]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or you have a house of gold or you ascend into the sky. And [even then], we will not believe in your ascension until you bring down to us a book we may read." Say, "Exalted is my Lord! Was I ever but a human messenger?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And what prevented the people from believing when guidance came to them except that they said, "Has Allah sent a human messenger?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "If there were upon the earth angels walking securely, We would have sent down to them from the heaven an angel [as a] messenger."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Sufficient is Allah as Witness between me and you. Indeed he is ever, concerning His servants, Acquainted and Seeing."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever Allah guides - he is the [rightly] guided; and whoever He sends astray - you will never find for them protectors besides Him, and We will gather them on the Day of Resurrection [fallen] on their faces - blind, dumb and deaf. Their refuge is Hell; every time it subsides We increase them in blazing fire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is their recompense because they disbelieved in Our verses and said, "When we are bones and crumbled particles, will we [truly] be resurrected [in] a new creation?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they not see that Allah, who created the heavens and earth, is [the one] Able to create the likes of them? And He has appointed for them a term, about which there is no doubt. But the wrongdoers refuse [anything] except disbelief.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say [to them], "If you possessed the depositories of the mercy of my Lord, then you would withhold out of fear of spending." And ever has man been stingy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had certainly given Moses nine evident signs, so ask the Children of Israel [about] when he came to them and Pharaoh said to him, "Indeed I think, O Moses, that you are affected by magic."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Moses] said, "You have already known that none has sent down these [signs] except the Lord of the heavens and the earth as evidence, and indeed I think, O Pharaoh, that you are destroyed."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So he intended to drive them from the land, but We drowned him and those with him all together.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We said after Pharaoh to the Children of Israel, "Dwell in the land, and when there comes the promise of the Hereafter, We will bring you forth in [one] gathering."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And with the truth We have sent the Qur''an down, and with the truth it has descended. And We have not sent you, [O Muhammad], except as a bringer of good tidings and a warner.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [it is] a Qur''an which We have separated [by intervals] that you might recite it to the people over a prolonged period. And We have sent it down progressively.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Believe in it or do not believe. Indeed, those who were given knowledge before it - when it is recited to them, they fall upon their faces in prostration,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "Exalted is our Lord! Indeed, the promise of our Lord has been fulfilled."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they fall upon their faces weeping, and the Qur''an increases them in humble submission.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Call upon Allah or call upon the Most Merciful. Whichever [name] you call - to Him belong the best names." And do not recite [too] loudly in your prayer or [too] quietly but seek between that an [intermediate] way.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 17 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And say, "Praise to Allah, who has not taken a son and has had no partner in [His] dominion and has no [need of a] protector out of weakness; and glorify Him with [great] glorification."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[All] praise is [due] to Allah, who has sent down upon His Servant the Book and has not made therein any deviance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He has made it] straight, to warn of severe punishment from Him and to give good tidings to the believers who do righteous deeds that they will have a good reward', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In which they will remain forever', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to warn those who say, "Allah has taken a son."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They have no knowledge of it, nor had their fathers. Grave is the word that comes out of their mouths; they speak not except a lie.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then perhaps you would kill yourself through grief over them, [O Muhammad], if they do not believe in this message, [and] out of sorrow.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have made that which is on the earth adornment for it that We may test them [as to] which of them is best in deed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, We will make that which is upon it [into] a barren ground.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or have you thought that the companions of the cave and the inscription were, among Our signs, a wonder?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Mention] when the youths retreated to the cave and said, "Our Lord, grant us from Yourself mercy and prepare for us from our affair right guidance."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So We cast [a cover of sleep] over their ears within the cave for a number of years.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We awakened them that We might show which of the two factions was most precise in calculating what [extent] they had remained in time.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is We who relate to you, [O Muhammad], their story in truth. Indeed, they were youths who believed in their Lord, and We increased them in guidance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We made firm their hearts when they stood up and said, "Our Lord is the Lord of the heavens and the earth. Never will we invoke besides Him any deity. We would have certainly spoken, then, an excessive transgression.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'These, our people, have taken besides Him deities. Why do they not bring for [worship of] them a clear authority? And who is more unjust than one who invents about Allah a lie?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[The youths said to one another], "And when you have withdrawn from them and that which they worship other than Allah, retreat to the cave. Your Lord will spread out for you of His mercy and will prepare for you from your affair facility."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [had you been present], you would see the sun when it rose, inclining away from their cave on the right, and when it set, passing away from them on the left, while they were [laying] within an open space thereof. That was from the signs of Allah. He whom Allah guides is the [rightly] guided, but he whom He leaves astray - never will you find for him a protecting guide.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you would think them awake, while they were asleep. And We turned them to the right and to the left, while their dog stretched his forelegs at the entrance. If you had looked at them, you would have turned from them in flight and been filled by them with terror.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And similarly, We awakened them that they might question one another. Said a speaker from among them, "How long have you remained [here]?" They said, "We have remained a day or part of a day." They said, "Your Lord is most knowing of how long you remained. So send one of you with this silver coin of yours to the city and let him look to which is the best of food and bring you provision from it and let him be cautious. And let no one be aware of you.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, if they come to know of you, they will stone you or return you to their religion. And never would you succeed, then - ever."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And similarly, We caused them to be found that they [who found them] would know that the promise of Allah is truth and that of the Hour there is no doubt. [That was] when they disputed among themselves about their affair and [then] said, "Construct over them a structure. Their Lord is most knowing about them." Said those who prevailed in the matter, "We will surely take [for ourselves] over them a masjid."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say there were three, the fourth of them being their dog; and they will say there were five, the sixth of them being their dog - guessing at the unseen; and they will say there were seven, and the eighth of them was their dog. Say, [O Muhammad], "My Lord is most knowing of their number. None knows them except a few. So do not argue about them except with an obvious argument and do not inquire about them among [the speculators] from anyone."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And never say of anything, "Indeed, I will do that tomorrow,"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except [when adding], "If Allah wills." And remember your Lord when you forget [it] and say, "Perhaps my Lord will guide me to what is nearer than this to right conduct."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they remained in their cave for three hundred years and exceeded by nine.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Allah is most knowing of how long they remained. He has [knowledge of] the unseen [aspects] of the heavens and the earth. How Seeing is He and how Hearing! They have not besides Him any protector, and He shares not His legislation with anyone."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And recite, [O Muhammad], what has been revealed to you of the Book of your Lord. There is no changer of His words, and never will you find in other than Him a refuge.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And keep yourself patient [by being] with those who call upon their Lord in the morning and the evening, seeking His countenance. And let not your eyes pass beyond them, desiring adornments of the worldly life, and do not obey one whose heart We have made heedless of Our remembrance and who follows his desire and whose affair is ever [in] neglect.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And say, "The truth is from your Lord, so whoever wills - let him believe; and whoever wills - let him disbelieve." Indeed, We have prepared for the wrongdoers a fire whose walls will surround them. And if they call for relief, they will be relieved with water like murky oil, which scalds [their] faces. Wretched is the drink, and evil is the resting place.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who have believed and done righteous deeds - indeed, We will not allow to be lost the reward of any who did well in deeds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those will have gardens of perpetual residence; beneath them rivers will flow. They will be adorned therein with bracelets of gold and will wear green garments of fine silk and brocade, reclining therein on adorned couches. Excellent is the reward, and good is the resting place.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And present to them an example of two men: We granted to one of them two gardens of grapevines, and We bordered them with palm trees and placed between them [fields of] crops.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Each of the two gardens produced its fruit and did not fall short thereof in anything. And We caused to gush forth within them a river.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he had fruit, so he said to his companion while he was conversing with him, "I am greater than you in wealth and mightier in [numbers of] men."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he entered his garden while he was unjust to himself. He said, "I do not think that this will perish - ever.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And I do not think the Hour will occur. And even if I should be brought back to my Lord, I will surely find better than this as a return."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'His companion said to him while he was conversing with him, "Have you disbelieved in He who created you from dust and then from a sperm-drop and then proportioned you [as] a man?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for me, He is Allah, my Lord, and I do not associate with my Lord anyone.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And why did you, when you entered your garden, not say, ''What Allah willed [has occurred]; there is no power except in Allah ''? Although you see me less than you in wealth and children,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It may be that my Lord will give me [something] better than your garden and will send upon it a calamity from the sky, and it will become a smooth, dusty ground,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or its water will become sunken [into the earth], so you would never be able to seek it."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And his fruits were encompassed [by ruin], so he began to turn his hands about [in dismay] over what he had spent on it, while it had collapsed upon its trellises, and said, "Oh, I wish I had not associated with my Lord anyone."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there was for him no company to aid him other than Allah, nor could he defend himself.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There the authority is [completely] for Allah, the Truth. He is best in reward and best in outcome.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And present to them the example of the life of this world, [its being] like rain which We send down from the sky, and the vegetation of the earth mingles with it and [then] it becomes dry remnants, scattered by the winds. And Allah is ever, over all things, Perfect in Ability.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Wealth and children are [but] adornment of the worldly life. But the enduring good deeds are better to your Lord for reward and better for [one''s] hope.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [warn of] the Day when We will remove the mountains and you will see the earth prominent, and We will gather them and not leave behind from them anyone.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will be presented before your Lord in rows, [and He will say], "You have certainly come to Us just as We created you the first time. But you claimed that We would never make for you an appointment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the record [of deeds] will be placed [open], and you will see the criminals fearful of that within it, and they will say, "Oh, woe to us! What is this book that leaves nothing small or great except that it has enumerated it?" And they will find what they did present [before them]. And your Lord does injustice to no one.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention] when We said to the angels, "Prostrate to Adam," and they prostrated, except for Iblees. He was of the jinn and departed from the command of his Lord. Then will you take him and his descendants as allies other than Me while they are enemies to you? Wretched it is for the wrongdoers as an exchange.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'I did not make them witness to the creation of the heavens and the earth or to the creation of themselves, and I would not have taken the misguiders as assistants.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [warn of] the Day when He will say, "Call ''My partners'' whom you claimed," and they will invoke them, but they will not respond to them. And We will put between them [a valley of] destruction.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the criminals will see the Fire and will be certain that they are to fall therein. And they will not find from it a way elsewhere.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have certainly diversified in this Qur''an for the people from every [kind of] example; but man has ever been, most of anything, [prone to] dispute.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And nothing has prevented the people from believing when guidance came to them and from asking forgiveness of their Lord except that there [must] befall them the [accustomed] precedent of the former peoples or that the punishment should come [directly] before them.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We send not the messengers except as bringers of good tidings and warners. And those who disbelieve dispute by [using] falsehood to [attempt to] invalidate thereby the truth and have taken My verses, and that of which they are warned, in ridicule.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And who is more unjust than one who is reminded of the verses of his Lord but turns away from them and forgets what his hands have put forth? Indeed, We have placed over their hearts coverings, lest they understand it, and in their ears deafness. And if you invite them to guidance - they will never be guided, then - ever.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your Lord is the Forgiving, full of mercy. If He were to impose blame upon them for what they earned, He would have hastened for them the punishment. Rather, for them is an appointment from which they will never find an escape.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those cities - We destroyed them when they wronged, and We made for their destruction an appointed time.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention] when Moses said to his servant, "I will not cease [traveling] until I reach the junction of the two seas or continue for a long period."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when they reached the junction between them, they forgot their fish, and it took its course into the sea, slipping away.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when they had passed beyond it, [Moses] said to his boy, "Bring us our morning meal. We have certainly suffered in this, our journey, [much] fatigue."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "Did you see when we retired to the rock? Indeed, I forgot [there] the fish. And none made me forget it except Satan - that I should mention it. And it took its course into the sea amazingly".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Moses] said, "That is what we were seeking." So they returned, following their footprints.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they found a servant from among Our servants to whom we had given mercy from us and had taught him from Us a [certain] knowledge.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Moses said to him, "May I follow you on [the condition] that you teach me from what you have been taught of sound judgement?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "Indeed, with me you will never be able to have patience.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And how can you have patience for what you do not encompass in knowledge?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Moses] said, "You will find me, if Allah wills, patient, and I will not disobey you in [any] order."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "Then if you follow me, do not ask me about anything until I make to you about it mention."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So they set out, until when they had embarked on the ship, al-Khidh r tore it open. [Moses] said, "Have you torn it open to drown its people? You have certainly done a grave thing."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Al-Khidh r] said, "Did I not say that with me you would never be able to have patience?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Moses] said, "Do not blame me for what I forgot and do not cover me in my matter with difficulty."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 18 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So they set out, until when they met a boy, al-Khidh r killed him. [Moses] said, "Have you killed a pure soul for other than [having killed] a soul? You have certainly done a deplorable thing."', NOW(), NOW());
